ApiTester = {
    init: async function(app, container, verb="GET", path="") {
        app = app || session.app;
        container = container || $(".component[name=ApiTester]")
        container.addClass("large");
        
        var requestMethods = ["GET", "HEAD", "POST", "PUT", "DELETE", "CONNECT", "OPTIONS", "TRACE", "PATCH"];
        $("input[name=api]", container).val(session.apiRoot);
        $("input[name=verb]", container).val(verb);
        $("input[name=verb]", container).kendoDropDownList({
            dataSource: requestMethods,
            value: verb
        });

        $("input[name=path]", container).val(path);
        $("div[name=responseBody]", container).kendoTreeView({dataSource: { data: [] }, loadOnDemand: true })

        var ds = {
            data: [
                { name: "Authorization", value: "bearer " + session.token },
                { name: "Content-Type", value: "application/json" }
            ],
            schema: {
                model: {
                    fields: {
                        name: { type: "string" },
                        value: { type: "string" }
                    }
                }
            }
        };
        var headersGrid = new GridWidget($("[name=headers]", container), ds)
        headersGrid.toolbar = "<button name='add'><span class='k-icon k-i-plus'></span>[resource_displayname[add]]</button>";
        headersGrid.scrollable = true;
        headersGrid.editable = true;
        headersGrid.pageable = false;
        headersGrid.commands.push({ name: "delete", icon: "k-i-delete", text: "[resource_displayname[delete]]" });
        headersGrid.columns = [
            { field: "name", title: "[resource_displayname[name]]"},
            { field: "value", title: "[resource_displayname[value]]"}
        ]
        await headersGrid.init();

        $("button[name=send]", container).on('click', (e) => {
            ApiTester.send(e, container);
        });

        ApiTester.send(null, container);
    },

    send: function (e, container) {
        $("pre[name=responseHeaders]", container).text('');
        $("div[name=responseBody]", container).html('');
         $.ajax({
             url: $("input[name=api]", container).val() + $("input[name=path]", container).val(),
             type: $("input[name=verb]", container).val(),
             data: $("pre[name=body]", container).text(),
             error: function (xhr) {
                 if (xhr.getAllResponseHeaders().includes("application/json")) {
                     ApiTester.displayResults(xhr.responseJSON, "error", xhr, container);
                 }
                 else {
                     ApiTester.displayResults(xhr.responseText || xhr.state(), "error", xhr, container);
                 }
             },
             success: ApiTester.displayResults,
             beforeSend: function (xhr) {
                 var headers = $("[name=headersGrid]").data('kendoGrid').dataSource.data();
                 for(var i = 0; i < headers.length; i++) {
                     var matches = headers[i].value.match(/{[\w.]*}/gm);
                     if (matches !== null) {
                         matches.forEach(function (m) {
                             var expression = m.replace('{', '').replace('}', '');
                             headers[i].value = headers[i].value.replace(m, eval(expression));
                         });
                     }
                    xhr.setRequestHeader(headers[i].name, headers[i].value);
                 }
             }
         });
     },

     displayResults: function (body, status, xhr, container) {
        var headers = xhr.getAllResponseHeaders();
        $("pre[name=responseHeaders]", container).text(headers);
        $("label[name=statusCode]", container).text(xhr.status);
        if(status == "error") {
            $("span[name=statusCodeIcon]", container).removeClass("k-i-check");
            $("span[name=statusCodeIcon]", container).addClass("k-i-x");
        } else {
            $("span[name=statusCodeIcon]", container).removeClass("k-i-x");
            $("span[name=statusCodeIcon]", container).addClass("k-i-check");
        }

        if (headers.includes("application/json")) {
            var dataSource = ApiTester.toKendoDataSource(body);
            $("div[name=responseBody]", container).kendoTreeView({dataSource:new kendo.data.HierarchicalDataSource({ data: dataSource }) });
            //$("pre[name=responseBody]", container).text(JSON.stringify(body, null, '\t'));
        }
        else { $("div[name=responseBody]", container).text(xhr.responseText); }
    },

    toKendoDataSource: function(object) {
        if(typeof(object) !== "object") return object;

        var results = [];
        var keys = Object.keys(object);

        for(let i = 0; i < keys.length; i++) {
            var key = keys[i];

            if(typeof(object[key]) == "object" && object[key] != null) {
                var childItems = ApiTester.toKendoDataSource(object[key]);
                results.push({text: key, items: childItems, hasChildren: true, id: Math.floor(Math.random() * 1000), expanded: true });
            } else {
                results.push({id: Math.floor(Math.random() * 1000), text: key + ": " + JSON.stringify(object[key]), hasChildren: false, expanded: true });
            }
        }

        return results;
    }
}

AppList = {
    init: async function(app, container, appsDMSPath) {
        app = app || session.app;
        container = container || $(".component[name=AppList]");
        var apps =  await api.get(appsDMSPath);
        var appGrid = new GridWidget(container, { data: apps });
        appGrid.groupable = false;
        appGrid.pageable = false;
        appGrid.commands.push({name: "visit", icon: "k-i-share", text:"[resource_displayname[visit]]", href: "https://#=domain#/" });
        appGrid.commands.push({ name: "applyTheming", icon: "k-i-edit", text: "[resource_displayname[applytheming]]" });
        appGrid.commands.push({ name: "remove", icon: "k-i-delete", text: "[resource_displayname[delete]]" });
        appGrid.columns = [
            { field: "environment", width: 100, title: "[resource_displayname[environment]]" }, 
            { field: "domain", title: "[resource_displayname[domain]]" }, 
            { field: "appType", title: "[resource_displayname[apptype]]" }
        ];
        appGrid.toolbar ="<button name='add'><span class='k-icon k-i-add'></span>[resource_displayname[add]]</button><button name='save'><span class='k-icon k-i-save'></span>[resource_displayname[save]]</button>";
        appGrid.dataBound = function () {
            $("[name=remove]", appGrid.gridElement).on("click", async (e) => await AppList.removeApp(e, appGrid, appsDMSPath));
        };
        await appGrid.init();
        $("button[name=add]", appGrid.gridElement).on("click", async () => await AppList.addApp(appGrid, appsDMSPath));
        $("[name=save]", appGrid.gridElement).on("click", async () => await AppList.save(appGrid, appsDMSPath));
    },

    save: async function(appGrid, appsDMSPath) {
        await api.put(appsDMSPath, appGrid.dataSource().data()).then(() => {
            notification.success("[resource_displayname[saved]]");
            appGrid.kendoObject.refresh();
        }).catch((err) => { error(err); });
    },
    
    addApp: function (appGrid, appsDMSPath) {
        var model = kendo.observable({ environment: "", domain: "", appType: "" });
        var addAppDialog = new Dialog({ title: "[resource_displayname[addapp]]" });
        addAppDialog.template = $("[name=addAppDialog]").html();
        addAppDialog.events.confirm = async function () {
            appGrid.dataSource().insert(0, model);
            await AppList.save(appGrid, appsDMSPath);
            addAppDialog.events.close();
        };
        addAppDialog.init(() => {
            $("[name=appTypes]", addAppDialog.element).kendoDropDownList({ 
                dataSource: { data: ["[resource_displayname[buyerportal]]", "[resource_displayname[einvoicingportal]]", "[resource_displayname[fundmanagementsystem]]"] } 
            });
            kendo.bind(addAppDialog.element, model);
        });
    },

    removeApp: async function (e, appGrid, appsDMSPath) {
        var item = appGrid.dataItem($(e.currentTarget).closest("tr"));
        appGrid.dataSource().remove(item);
        await AppList.save(appGrid, appsDMSPath);
    }
}

AppManagement = {
    toolbar: true,

    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=AppManagement]")[0];
        app = await api.get("Core/App(" + app.Id + ")");
        app.Config = JSON.parse(app.ConfigJson);
        if (AppManagement.toolbar) {
            $("[name=appToolbar]").kendoToolBar({
                items: [
                    {
                        text: "[resource_displayname[save]]",
                        type: "button",
                        template: `
                            <div class="btn-group btn-group-sm">
                                <button class="btn btn-primary" name="appSave">
                                    <span class='k-icon k-i-save'></span> [resource_displayname[Save]]
                                </button>
                                <button class="btn btn-primary" name="appMigrate" data-bs-toggle="modal" data-bs-target="#app-migrator-model">
                                    <span class='k-icon k-i-arrow-up'></span> [resource_displayname[Migrate]]
                                </button>
                            </div>`
                    }
                ]
            });
        } else {
            $("[name=appToolbar]", container).remove();
        }

        this.initNavTabIds(app, container);
        await this.addClickListenerForComponents(app, container);

        if ($(".tab-pane[name=config] > div[name=editor]", container)[0].childElementCount === 0) {
            var configEditor = new MonacoEditor($(".tab-pane[name=config] > div[name=editor]", container)[0], {
                code: app.ConfigJson,
                language: "json",
                automaticLayout: true
            });
            configEditor.onChange = () => app.ConfigJson = configEditor.getValue();
            configEditor.init();
            $(".tab-pane[name=config] > div[name=editor]", container).data("configEditor", configEditor);
            $("[name=appSave]", container).click(() => AppManagement.save(app, configEditor));
            $("[name=appMigrate]", container).click(() => AppManagement.migrate(app, container));
        }
    },

    initNavTabIds: function(app, container) {
        var nav = $('#app-management-nav-tab', container);
        nav.attr('id', `${nav.attr('id')}-${app.Id}`);
        var content = $('#app-management-nav-tabContent', container);
        content.attr('id', `${content.attr('id')}-${app.Id}`);

        var buttons = $('button[role=tab]', nav);
        buttons.each((button) => {
            var button = $(buttons[button], container);
            button.attr('data-bs-target', `${button.attr('data-bs-target')}-${app.Id}`);
        });

        var tabs = $('.tab-pane', content);
        tabs.each((tab) => {
            var tab = $(tabs[tab], container);
            tab.attr('id', `${tab.attr('id')}-${app.Id}`);
        });
    },

    addClickListenerForComponents: async function(app, container) {
        var buttons = $('button[role=tab]', container);
        buttons.each((button) => {
            var button = $(buttons[button], container);
            var target = $(button.attr('data-bs-target'));
            var component = target.attr('data-component');

            if(component != null) {
                button.click(async () => {
                    console.log(`Loading component: ${component}`);

                    var existing = $(`.component[name=${component}]`, $(target, container));

                    if(existing.length == 0) {
                        await loadComponent($(target, container), component, async (c) => {
                            await c.init(app, $(`.component[name=${component}]`, $(target, container)));
                        });
                    }
                });
            }
        });
    },

    migrate: async function (app, container) {
        // var d = new Dialog({ title: "[resource_displayname[migrate]]", width: 620, height: "auto" });
        // d.template = $("[name=appMigratorComponent]").first().html();
        var element = $("[name=AppMigrator]", container);
        await AppMigrator.init(app, element, app);
    },

    save: async function (app, configEditor) {
        var newApp = {
            ConfigJson: configEditor.getValue(),
            Cultures: app.Cultures,
            DefaultCultureId: app.DefaultCultureId,
            DefaultTheme: app.DefaultTheme,
            Domain: app.Domain,
            Id: app.Id,
            Name: app.Name,
            TenantId: app.TenantId
        };
        try {
            JSON.parse(newApp.ConfigJson);
        } catch(err) {
            error("[resource_displayname[AppConfigParsingError]]");
            return;
        }
        notification.info("[resource_displayname[saving]]");
        await api.update("Core/App(" + app.Id + ")", newApp).then(() => {
            notification.success("[resource_displayname[saved]]")
        }).catch((err) => error(err));
    }
};

AppMigrator = {
    init: async function (app, container, appToMigrate, dialog) {
        app = app || session.app;
        container = container || $(".component[name=AppMigrator]");
        if(!appToMigrate)
            return;

        var environments = JSON.parse(appToMigrate.ConfigJson).Deployment.Targets;
        var apiSelect = $('[name=api]', container);

        environments.forEach((env) => {
            apiSelect.append('<option value="' + env.Api + '">' + env.EnvironmentName + '</option>');
        });

        var packages = await api.get("Core/App(" + appToMigrate.Id + ")/Export()");
        packages.value.push({ Name: "DMS" });
        var packageGrid = new GridWidget($("[name=selectPackagesGrid]", container), {
            data: packages.value,
            sort: {
                field: "Name",
                dir: "asc"
            }
        });
        packageGrid.groupable = false;
        packageGrid.pageable = false;
        packageGrid.editable = false;
        packageGrid.columns = [
            {
                selectable: true,
                width: 50
            },
            {
                field: "Name"
            }
        ];
        packageGrid.init(() => {
            packageGrid.kendoObject.select(packageGrid.kendoObject.tbody.find(">tr"));
        });
        $("button[name=migrate]", container).off().on("click", async function (e) {
            if(dialog)
                dialog.events.close();
            
            await AppMigrator.migrate(app, container, appToMigrate, packageGrid);
        });
    },

    migrate: async function (app, container, sourceApp, packageGrid) {
        var packagesSelected = [];
        packageGrid.kendoObject.select().each(function () {
            packagesSelected.push(packageGrid.kendoObject.dataItem(this).Name);
        });
        var functions = {
            [script[MigrateApp]]
        };
        var vars = {
            Domain: JSON.parse(sourceApp.ConfigJson).Deployment.Targets.filter(
                r => r.Api == $("[name=api]", container).val()
            )[0].Domain,
            RemoteAuth: {
                User: session.user,
                Pass: $("[name=pass]", container).val(),
                Api: JSON.parse(sourceApp.ConfigJson).Deployment.Targets.filter(
                    r => r.Api == $("[name=api]", container).val()
                )[0].Api,
            },
            SelectedPackageNames: packagesSelected,
            SourceApp: sourceApp
        };
        if(packagesSelected.filter(r => r == "DMS").length > 0) {
            vars.DMSPaths = JSON.parse(sourceApp.ConfigJson).Deployment.DMS;
        }
        var d = new Dialog({
            width: 800,
            height: 500,
            title: "[resource_displayname[migrating]]"
        });
        d.init(async () => {
            await loadComponent($(d.element), "ScriptRunner", (scriptRunner) =>
                scriptRunner.init(app, $(".component[name=ScriptRunner]", d.element), vars, functions, d));
        });
    }
}

AppThemeList = {
    init: async function(app, container) {
        app = app || session.app;
        container = container || $(".component[name=AppThemeList]");
        var appKeys = Object.keys(app.Config.Themes);
        var appThemes = appKeys.map(k => ({
            name: k,
            theme: app.Config.Themes[k]
        }));
        var themeGrid = new GridWidget(container, appThemes);
        themeGrid.toolbar = [
			{
				template: `<div class="btn-group btn-group-sm">
                    <button class="btn btn-primary" name="add">
                        <span class="k-icon k-i-plus"></span>[resource_displayname[new]]
                    </button>
                </div>`
			}
		];
        themeGrid.groupable = false;
        themeGrid.pageable = false;
        themeGrid.sortable = true;
        themeGrid.columns = [{ field: "name", title: "[resource_displayname[name]]" }];
        themeGrid.commands.push({ name: "edit", icon: "k-i-pencil", text: "[resource_displayname[edit]]" });
        themeGrid.commands.push({ name: "remove", icon: "k-i-trash", text: "[resource_displayname[delete]]" });
        themeGrid.dataBound = function () {
            $("[name=edit]", themeGrid.gridElement).on("click", (e) => AppThemeList.editTheme(e, app, themeGrid));
            $("[name=remove]", themeGrid.gridElement).on("click", (e) => AppThemeList.removeTheme(e, app, themeGrid));
        };
        await themeGrid.init();
        $("button[name=add]", themeGrid.gridElement).on("click", () => AppThemeList.addTheme(app, themeGrid));
    },

    editTheme: async function(e, app, themeGrid) {
        e.preventDefault();
        var item = themeGrid.dataItem($(e.currentTarget).closest("tr"));
        var d = new BootstrapDialog({
            title: "[resource_displayname[edittheme]]"
        });
        d.name = "EditTheme";
        d.template = $("[name=editThemeTemplate]").first().html();
        d.footer = `
            <button type="button" class="btn btn-sm btn-primary" name="save">
                <span class="k-icon k-i-save"></span>[resource_displayname[save]]
            </button>    
        `;
        d.width = 'xl'
        d.init(async () => {
            var c = await loadComponent($("[name=themeContent]", d.element), "ThemeBuilder");
            c.init(app, $(".component[name=ThemeBuilder]", d.element), item.theme);
            $("[name=save]", d.element).on("click",  async function(e) {
                item.theme = ThemeBuilder.build($(".component[name=ThemeBuilder]", d.element));
                await AppThemeList.save(app, themeGrid);
            });
        });
        d.modal.show();
    },

    save: async function(app, themeGrid) {
        var themes = themeGrid.dataSource().data();
        var dictionary = {};
        for(let i = 0; i < themes.length; i++) {
            dictionary[themes[i].name] = themes[i].theme;
        }
        var app = await api.get("Core/App(" + app.Id + ")");
        var config = JSON.parse(app.ConfigJson);
        config.Themes = dictionary;
        app.ConfigJson = JSON.stringify(config, null, 4);
        await api.put("Core/App(" + app.Id + ")", app).then(() => {
            notification.success("[resource_displayname[saved]]");
            var appKeys = Object.keys(config.Themes);
            var appThemes = appKeys.map(k => ({name: k, theme: config.Themes[k]}));
            themeGrid.kendoObject.setDataSource({data: appThemes});
        }).catch((err) => error(err));
    },

    addTheme: function (app, themeGrid) {
        var model = kendo.observable({ name: "", theme: JSON.parse(JSON.stringify(app.Config.Themes.Default)) });
        var addThemeDialog = new Dialog({ title: "[resource_displayname[addtheme]]" });
        addThemeDialog.template = $("[name=addThemeDialog]").html();
        addThemeDialog.events.confirm = async function () {
            themeGrid.dataSource().insert(0, model);
            await AppThemeList.save(app, themeGrid);
            addThemeDialog.events.close();
        };
        addThemeDialog.init(() => {  
            kendo.bind(addThemeDialog.element, model);  
        });
    },

    removeTheme: async function (e, app, themeGrid) {
        e.preventDefault();

		var d = new ConfirmDialog({
			title: "[resource_displayname[areyousure]]",
			confirm: "[resource_displayname[confirm]]",
			close: "[resource_displayname[close]]"
		});

		d.events.confirm = async function () {
			var item = themeGrid.dataItem($(e.currentTarget).closest("tr"));
            themeGrid.dataSource().remove(item);
            await AppThemeList.save(app, themeGrid);
			d.events.close();
		};

		d.init();
    }
}

AppTheming = {
    init: async function(app, container) {
        app = app || session.app;
        container = container || $(".component[name=AppTheming]");

        var themeListContainer = $('[name=app-theme-list]', container);
        await loadComponent(themeListContainer, 'AppThemeList', async (c) => {
            await c.init(app, $(`.component[name=AppThemeList]`, themeListContainer));
        });

        AppTheming.wireUpEvents(container);
    },

    wireUpEvents: function(container) {
        AppTheming.wireUpFileUploading(
            $('input[name=brand-logo]', container),
            $('img[name=brand-logo-preview]', container),
            'Content/CompanyLogo.png');

        AppTheming.wireUpFileUploading(
            $('input[name=project-logo]', container),
            $('img[name=project-logo-preview]', container),
            'Content/CompanyLogo2.png');

        AppTheming.wireUpFileUploading(
            $('input[name=animation]', container),
            $('img[name=animation-preview]', container),
            'Content/background.gif');
    },

    wireUpFileUploading: function(element, preview, path) { 
        element.on('change', (e) => AppTheming.handleFileUploadEvent(e, preview, path));
        element.on('dragend',(e) => AppTheming.handleFileUploadEvent(e, preview, path));
    },

    handleFileUploadEvent: async function(event, element, path) {
        if(event.target.files.length > 1) {
            notification.error('[resource_displayname[onlyonefile]]');
            return;
        }

        var file = event.target.files[0] || null;
        if(file == null)
            return;

        AppTheming.handleFileUploadPreview(file, element);
        await api.file.upload(path, file);
    },

    handleFileUploadPreview: function(file, element) {
        var preview = URL.createObjectURL(file);
        element.attr('src', preview);
    }
};

Border = {
    init: async function (app, container, observable) {
        app = app || session.app;
        container = container || $(".component[name=Border]");
        if(!observable)
            return;

        $("[name=borderStyleDropdown]", container).kendoDropDownList({
            dataTextField: "text",
            dataValueField: "name",
            change: function(e) {
                e.preventDefault();
                var existingBorderValue = observable.get("border.style");
                var parts = existingBorderValue.split(" ");
                parts[0] = this.value();
                observable.set("border.style", parts.join(" "));
            },
            dataSource: {
                data: [
                    { name: "dotted", text: "[resource_displayname[dotted]]" },
                    { name: "dashed", text: "[resource_displayname[dashed]]" },
                    { name: "solid", text: "[resource_displayname[solid]]" },
                    { name: "double", text: "[resource_displayname[double]]" },
                    { name: "groove", text: "[resource_displayname[groove]]" },
                    { name: "ridge", text: "[resource_displayname[ridge]]" },
                    { name: "inset", text: "[resource_displayname[inset]]" },
                    { name: "outset", text: "[resource_displayname[outset]]" },
                    { name: "none", text: "[resource_displayname[none]]" },
                    { name: "hidden", text: "[resource_displayname[hidden]]" }
                ]
            }
        });

        $("[name=borderColorPicker]", container).kendoColorPicker({
            buttons: false,
            value: observable.get("border.style").split(" ")[2],
            change: function(e) {
                e.preventDefault();
                var existingBorderValue = observable.get("border.style");
                var parts = existingBorderValue.split(" ");
                parts[2] = this.value();
                observable.set("border.style", parts.join(" "));
            }
        });

        await Border.initSliders(container, observable);
    },

    initSliders: async function(container, observable) {
        $("[name=borderWidthSlider]", container).kendoSlider({ 
            min: 0, 
            max: 20, 
            smallStep: 1, 
            largeStep: 2, 
            value: parseFloat(observable.get("border.style").split(" ")[1].replaceAll("px", "")),
            change: function(e) {
                e.preventDefault();
                var existingBorderValue = (observable.get("border.style") || "solid 0px");
                var parts = existingBorderValue.split(" ");
                parts[1] = this.value() + "px";
                observable.set("border.style", parts.join(" "));
                observable.set("border.width", this.value() + "px");
            }
        });

        $("[name=borderRadiusSlider]", container).kendoSlider({ 
            min: 0, 
            max: 20, 
            smallStep: 1, 
            largeStep: 2, 
            value: parseFloat((observable.get("border.radius") || "0px").replaceAll("px", "")),
            change: function(e) {
                e.preventDefault();
                var existingBorderValue = (observable.get("border.radius") || "0px");
                var parts = existingBorderValue.split(" ");
                parts[1] = this.value() + "px";
                observable.set("border.radius", this.value() + "px");
            }
        });
    }
}

BPM = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=BPM]");
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/BusinessProcess]]
				]
			}
		]);
		if(!window.knownTypes) {
            window.knownTypes = await api.get('GetMetadata');
        }
		await BPM.setupGrid(app, container);
	},

	setupGrid: async function (app, container) {
		var processes = await model.getDatasource({
            endpoint: "Core/BusinessProcess",
            odataAppend: "?$filter=AppId eq " + app.Id
        });
		var grid = new GridWidget(container, processes);
		grid.groupable = false;
		grid.pageable = false;
