	sunday: 0,

	populateCalendarDates: function(container, startDate, endDate) {
		var current = new Date(startDate.toISOString()); // Create a copy of the start date
		var end = endDate
			? new Date(endDate)
			: null;

		if(end == null) {
			end = new Date(CalendarManagement.formatDateToYMD(startDate));
			end.setMonth(end.getMonth() + 1);
			end.setDate(0);
		}

		var week = 0;

		// Step 1: Fill week 0 correctly (even if the month doesn't start on Sunday)
		while (current <= end) {
			var dayOfWeek = current.getDay();
			if (current.getDate() === 1 && dayOfWeek !== CalendarManagement.sunday) {
				// Ensure the first week is filled even if the month doesn't start on Sunday
				for (var emptyDay = 0; emptyDay < dayOfWeek; emptyDay++) {
					var placeholderDate = $(`[name=${week}-${emptyDay}]`, container);
					placeholderDate.html('{DATE}');
				}
			}

			// Step 2: Fill the current date in the grid
			var calendarDate = $(`[name=${week}-${dayOfWeek}]`, container);
			calendarDate.html(calendarDate.html().replaceAll('{DATE}', current.getDate()));

			// Set the correct data-date for the element
			var fullDate = CalendarManagement.formatDateToYMD(current);
			calendarDate.attr('data-date', fullDate);
			$('button[name=add-event]', calendarDate).attr('data-date', fullDate);

			// Step 3: Move to the next day
			current.setDate(current.getDate() + 1);

			// Step 4: Increment the week counter if the day is Sunday (end of week)
			if (dayOfWeek === 6 && current <= end) {
				week++;
			}
		}

		// Step 5: Clear out any remaining placeholders (those that still contain '{DATE}')
		var invalid = $(container).find('.col-calendar:contains({DATE})');
		invalid.each(function() {
			$(this).html(''); // Clear the placeholders
		});

		// Step 6: Clear out any fully invalid rows
		var rows = $(container).find('.row');
		rows.each(function() {
			var dates = $(this).find('.col-calendar');

			var rowIsEmpty = true;
			for(var date of dates) {
				if($(date).html() != '')
					rowIsEmpty = false;
			}

			if(rowIsEmpty)
				$(this).remove();
		});
	},

	populateCalendarEvents: function(container, events) {
		for(var event of events) {
			var eventDate = new Date(event.Start.split('T')[0]).toISOString().split('T');

			var eventCode = `<div class="calendarEvent">
				<button class="btn btn-sm btn-primary float-end" name="delete-event" data-eventid="${event.Id}">
					<span class="k-icon k-i-trash"></span>
				</button>
				<span class="k-icon k-i-calendar"></span>
				<label>${event.Name}</label>
			</div>`;

			var dateBlock = $(`.col-calendar[data-date=${eventDate[0]}] > .events`, container);
			dateBlock.append(eventCode);
		}
	},

	buildCalendar: async function(container, args) {
		// Reset the calendar state.
		CalendarManagement.initialiseCalendarGrid(container);

		var selectedYear = $('[name=year]', container).val();
		var selectedMonth = $('[name=month]', container).val().padStart(2, '0');
		var selectedCalendar = args.calendarId;

		var start = (args && args.fromDate)
			? new Date(args.fromDate)
			: new Date(selectedYear, selectedMonth - 1, 1);

		var end = (args && args.toDate) 
			? new Date(args.toDate) 
			: new Date(start.getFullYear(), start.getMonth() + 1, 0);

		CalendarManagement.populateCalendarDates($('[name=calendar]', container), start, end);

		var events;
		if (args && args.eventSource) {
			events = args.eventSource;
		} else {
			events = (await api.get(`Scheduling/CalendarEvent?$filter=CalendarId eq ${selectedCalendar} and Start ge ${CalendarManagement.formatDateToYMD(start)} and Start le ${CalendarManagement.formatDateToYMD(end)}`)).value;
		}

		await CalendarManagement.populateCalendarEvents(container, events);
		CalendarManagement.wireUpClickEvents(container, args);
	},

	wireUpClickEvents: async function(container, args) {
		$('[name=add-event]', container).on('click', async (e) => {
			var selectedCalendar = $('[name=calendars]', container).val();
			var eventDate = $(e.target).attr('data-date');
			await CalendarManagement.newCalendarEvent(e, selectedCalendar, eventDate, container, args);
		});

		$('[name=delete-event]', container).on('click', async (e) => {
			var eventId = $(e.target).attr('data-eventid');
			await CalendarManagement.deleteCalendarEvent(e, eventId, container, args);
		});

		if(args && args.readOnly) {
			$('[name=add-event]', container).remove();
			$('[name=delete-event]', container).remove();
		}
	},

