	newCalendarEvent: async function (e, calendarId, start, container, args) {
		e.preventDefault();
		var startInformation = new Date(start);
		var trueStart = new Date(Date.UTC(startInformation.getUTCFullYear(), startInformation.getUTCMonth(), startInformation.getUTCDate()));
		var calendarEvent = kendo.observable({
			Id: 0,
			CalendarId: args.calendarId,
			Name: "",
			Start: trueStart.toISOString(),
			DurationInTicks: 1000000 * 24 * 60 * 60
		});

		var addCalendarEventDialog = new Dialog({ title: "[resource_displayname[neweventfor]] " + CalendarManagement.days[new Date(start).getDay()] });
		addCalendarEventDialog.template = $("[name=newCalendarEventDialog]", container).first().html();
		addCalendarEventDialog.events.confirm = async function () {
			calendarEvent = calendarEvent.toJSON();
			var repeatsEvery = $("[name=repeatsEvery]", addCalendarEventDialog.element).val();

			if (repeatsEvery == "never") {
				await api.add("Scheduling/CalendarEvent", calendarEvent)
					.then(async () => {
						addCalendarEventDialog.events.close();
						notification.success("[resource_displayname[created]]");
						await CalendarManagement.buildCalendar(container, args);
					})
					.catch((err) => error(err));
			} else if (repeatsEvery == "weekly") {
				var start = new Date(trueStart);
				var untilDate = $("[name=until]", addCalendarEventDialog.element).data("kendoDateTimePicker").value();
				var events = [];
				while (start < untilDate) {
					events.push({
						Id: calendarEvent.Id,
						CalendarId: calendarEvent.CalendarId,
						Name: calendarEvent.Name,
						Start: start.toISOString(),
						DurationInTicks: calendarEvent.DurationInTicks
					});
					start.setDate(start.getDate() + 7);
				}
				notification.info("[resource_displayname[adding]]");

				// Post all events to "Scheduling/CalendarEvent" individually
				for (let i = 0; i < events.length; i++) {
					await api.add("Scheduling/CalendarEvent", events[i])
						.catch((err) => error(err));
				}

				addCalendarEventDialog.events.close();
				notification.success("[resource_displayname[created]]");
				await CalendarManagement.buildCalendar(container, args);
			}
		};

		addCalendarEventDialog.init(() => {
			kendo.bind(addCalendarEventDialog.element, calendarEvent);
			$("[name=repeatsEvery]", addCalendarEventDialog.element).kendoDropDownList({
				dataSource: Object.keys(CalendarManagement.repeats).map(r => ({
					Text: CalendarManagement.repeats[r],
					Value: r
				})),
				dataTextField: "Text",
				dataValueField: "Value"
			});
			$("[name=until]", addCalendarEventDialog.element).kendoDatePicker({
				autoBind: false,
				value: new Date(),
				dateInput: true,
				format: type.dateFormat
			});
		});
	},


	deleteCalendarEvent: async function (e, eventId, container, args) {
		e.preventDefault();
		await api.destroy("Scheduling/CalendarEvent(" + eventId + ")").then(async () => {
			notification.success("[resource_displayname[deleted]]");
			await CalendarManagement.buildCalendar(container, args);
		}).catch((err) => error(err));
	},

	formatDateToYMD: function(date) {
		return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')}`;
	}
}

