                $("button[name=add]", clientGrid.gridElement).on("click", (e) => ClientList.addClient(container, clientGrid, app));
            });
    },


    addClient: function (container, grid, app) {
        var clientNameDialog = new Dialog({ title: "[resource_displayname[ClientName]]" });
        clientNameDialog.template = $("[name=clientNameDialog]", container).html();
        clientNameDialog.events.confirm = async function () {
            var name = $("[name=clientName]", clientNameDialog.element).val();
            clientNameDialog.events.close();
            var clientList = await api.get("DMS/" + app.Config.CRM.ClientFolder + "clientList.json");
            clientList.push({ 
                name: name, 
                created: (new Date()).toISOString(), 
                state: "Unscanned", 
                details: "crm/clients/" + name, 
                lastUpdated: (new Date()).toISOString()
            });
            await api.put("DMS/" + app.Config.CRM.ClientFolder + "clientList.json", clientList);
            await api.put("DMS/" + app.Config.CRM.ClientFolder + name + "/apps.json",[]);
            await api.put("DMS/" + app.Config.CRM.ClientFolder + name + "/history.json",[]);
            await api.put("DMS/" + app.Config.CRM.ClientFolder + name + "/themes.json",[]);
            grid.kendoObject.setDataSource({ data: clientList });
            grid.refresh();
        };
        clientNameDialog.init();
    },

    viewClient: function (e, grid) {
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        window.location.href = window.location.protocol + "//" + window.location.hostname + "/Admin/Client?Name=" + item.name;
    },

    scanClient: async function (e, grid, app, clientEntry) {
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        var scanClientScript = [dms[scripts/crm/scanclient.js]];
        var environmentInfo = JSON.parse(await api.get("DMS/" + JSON.parse(app.ConfigJson).CRM.ClientFolder + "/environments.json")).CurrentEnvironment;
        var appId = item.apps.filter(r=>r.environment == environmentInfo)[0].appId;
        clientEntry.state = await scanClientScript(appId);
        await api.put("DMS/" + app.Config.CRM.ClientFolder + "clientList.json",clientList);
    },

    removeClient: async function (e, grid, app, clientList) {
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        for (var i = 0; i < clientList.length; i++) {
            if (clientList[i].name == item.name) {
                clientList.splice(i, 1);
            }
        }
        await api.put("DMS/" + app.Config.CRM.ClientFolder + "clientList.json", clientList);
        await api.destroy("DMS/" + app.Config.CRM.ClientFolder + item.name);
        grid.kendoObject.setDataSource({ data: clientList });
        grid.refresh();
    }
}

