var CMS = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=CMS]");

		app = await api.get("Core/App(" + app.Id + ")");
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[ContentManagement/Page]],
					[meta[Core/Layout]]
				]
			}]);

		// $(window).on("resize", () => CMS.resize(container));
		// CMS.resize(container);

		var treeRoot = $(".pageTree", container);

		$("[name=splitter]", container).kendoSplitter({
			scrollable: false,
			panes: [
				{ collapsible: false },
				{ collapsible: false, scrollable: false }
			]
		});

		var tree = new ODataTree(
			new ODataTreeOptions()
				.setElement(treeRoot)
				.setEndpoint("ContentManagement/Page")
				.setODataAppend("?$filter=AppId eq " + app.Id + "&$expand=Pages($orderBy=Order asc),PageInfo,Contents&$orderBy=Order asc")
		);

		let pageTypeData = await api.getType("ContentManagement/Page");

		tree.prepareData = (p) => {
			var hasChildren = p.Pages.length > 0;
			var pageName = p.PageInfo.filter(r => r.CultureId === "")[0].Title;
			if (p.PageInfo && p.PageInfo.length > 0) {
				var matchedPageInfo = p.PageInfo.filter(r => r.CultureId === session.culture);
				pageName = matchedPageInfo.length > 0 ? matchedPageInfo[0].Title : pageName;
			}
			model.prepareItem(p, pageTypeData);
			return { text: pageName, spriteCssClass: "page", type: "Page", data: p, expanded: false, hasChildren: hasChildren };
		};

		tree.select = (e) => CMS.tree.selectNode(e, tree);
		tree.drop = (e) => CMS.tree.drop(e, tree);
		treeRoot.on("contextmenu", ".k-treeview-leaf", (e) => CMS.tree.rightClick(e, app, tree, container));

		await tree.init();
	},

	resize: function (container) {
		var headerHeight = $("body > header").height();
		var footerHeight = $("body > footer").height();
		var bodyHeight = $("body").height();
		container.height(bodyHeight - (headerHeight + footerHeight) - 3);
		container.width("100%");
	},

	tree: {
		updatePages: async function (treePages) {
			for (let i = 0; i < treePages.length; i++) {
				treePages[i].data.Order = i;
			}

			for (let i = 0; i < updateData.length; i++) {
				await updateData[i].save();
			}
		},

		drop: async function (e, tree) {
			e.preventDefault();
			var dropNode = tree.dataItem($(e.dropTarget).closest(".k-item"));
			var dragNode = tree.dataItem($(e.sourceNode));
			var parent = $(e.sourceNode).parent();
			var targetParent = $(e.destinationNode).parent();
			var index = tree.dataItem(parent).items.indexOf(dragNode);
			if (e.dropPosition === "over") {
				// apply move
				tree.dataItem(parent).items.splice(index, 1);
				if (dropNode.type != "Root") {
					dragNode.data.ParentId = dropNode.data.Id;
				}
				else {
					dragNode.data.ParentId = null;
				}
				dragNode.data.save();

			} else if (e.dropPosition === "after") {
				var newIndex = tree.dataItem(targetParent).items.indexOf(tree.dataItem(e.destinationNode));
				if (newIndex < tree.dataItem(targetParent).items.length) {
					tree.dataItem(parent).items.splice(index, 1);
					tree.dataItem(targetParent).items.splice(newIndex, 0, dragNode);
					dragNode.data.Order = newIndex;
					dragNode.data.ParentId = tree.dataItem(targetParent).data.Id;
					await CMS.tree.updatePages(tree.dataItem(targetParent).items);
				}
			} else if (e.dropPosition === "before") {
				var newIndex = tree.dataItem(targetParent).items.indexOf(tree.dataItem(e.destinationNode)) - 1;
				if (newIndex >= 0) {
					tree.dataItem(parent).items.splice(index, 1);
					tree.dataItem(targetParent).items.splice(newIndex + 1, 0, dragNode);
					dragNode.data.Order = newIndex;
				} else {
					tree.dataItem(parent).items.splice(index, 1);
					tree.dataItem(targetParent).items.splice(0, 0, dragNode);
					dragNode.data.Order = 0;
				}
				dragNode.data.ParentId = tree.dataItem(targetParent).data.Id;
				await CMS.tree.updatePages(tree.dataItem(targetParent).items);
			}
		},

		rightClick: async function (e, app, tree, container) {
			e.preventDefault();
			var page = tree.dataItem(e.target).data;

			var contextMenu = new ContextMenuWidget(container);
						contextMenu.commands.push({ name: "newChild", icon: "k-i-plusIcon", text: "[resource_displayname[newchildpage]]" });
			contextMenu.commands.push({ name: "delete", icon: "k-i-trashIcon", text: "[resource_displayname[delete]]" });
			contextMenu.commands.push({ name: "properties", icon: "k-i-fileConfigIcon", text: "[resource_displayname[properties]]" });
			contextMenu.init(e.pageX, e.pageY);

			$("[name=newChild]", contextMenu.contextMenuElement).on("click", (e) => CMS.tree.newChild(e, app, page, tree));
			$("[name=delete]", contextMenu.contextMenuElement).on("click", (e) => CMS.tree.destroy(e, page, tree));
			$("[name=properties]", contextMenu.contextMenuElement).on("click", (e) => CMS.tree.properties(e, page, app));
		},

		newChild: async function (e, app, page, tree) {
			e.preventDefault();

			var dataItem = tree.dataItem(e.target);
			var meta = await api.getType("ContentManagement/Page");
			var layoutDataSource = await model.getDatasource({ endpoint: "Core/Layout", odataAppend: "?$filter=AppId eq " + app.Id });

			var newPage = new kendo.data.ObservableObject({
				Id: "new",
				Name: "",
				ParentId: (page != null) ? page.Id : null,
				AppId: app.Id,
				ShowOnMenus: true,
				Layout: "Default",
				Order: 0,
				PageInfo: [
					{ CultureId: "", Title: "", Description: "", Keywords: "" }
				],
				Contents: [
					{ CultureId: "", Html: "", Name: "body" }
				]
			});

			var newChildDialog = new Dialog({ width: 510, height: 300, title: "[resource_displayname[newpage]]" });
			newChildDialog.template = $("[name=newChildPageTemplate]").first().html();

			newChildDialog.events.submit = async () => {
				model.prepareItem(newPage, meta);
				await newPage.save();
				dataItem.append({ text: newPage.PageInfo[0].Title, type: "Page", spriteCssClass: "page", expanded: false, hasChildren: true, data: newPage, draggable: true, droppable: ["Page"] });
				notification.success("[resource_displayname[created]]");
			};

			newChildDialog.init(() => {
				kendo.bind(newChildDialog.element, newPage);
				$("[name=layout]", newChildDialog.element).kendoDropDownList({ dataTextField: "Name", dataValueField: "Name", dataSource: layoutDataSource });
			});
		},

		destroy: function (e, page, tree) {
			e.preventDefault();
			var d = new ConfirmDialog({ question: "[resource_description[areyousure]]", title: "[resource_description[areyousure]]: " + page.Path, confirm: "[resource_displayname[confirm]]", close: "[resource_displayname[close]]" });

			d.events.confirm = async function (e) {
				await page.destroy(e);
				notification.success("[resource_description[PageDeleted]]");
				d.events.close();
				tree.remove(e.target);
			};
			d.init();
		},

		properties: function (e, page, app) {
			e.preventDefault();
			var d = new Dialog();
			d.width = 900;
			d.height = 'auto';
			d.title = "[resource_displayname[pageproperties]]: " + page.Path;
			d.component = "PageProperties";
			d.init(() => PageProperties.init(app, $(".component[name=PageProperties]", $(d.element)), page));
		},

		selectNode: function (e, tree) {
			var page = tree.dataItem(e.node).data;
			$(".panel[name=workspace]").html("<iframe src='[app[root]]" + page.Path + "?edit=true'></iframe>");
		}
	}
};

