CommonCacheComponents = {
    init: async function(app, container) {
        app = app || session.app;
        container = container || $(".component[name=CommonCacheComponents]");
        
        var componentData = await CommonCacheComponents.getDataSource("Core/CommonObject/Latest()?type=ContentManagement/Component&$orderby=Name asc");
        await CommonCacheComponents.setupComponentGrid(componentData, container);
    },

    getDataSource(url) {
        return new kendo.data.DataSource({
            transport: {
                read: { url: api.apiRoot + url, dataType: "json" }
            },
            pageSize: 50,
            schema: {
                data: function (response) {
                    for(let i = 0; i < response.value.length; i = i + 1) {
                        response.value[i].CreatedOn = new Date(response.value[i].CreatedOn);
                        response.value[i].LastUpdated = new Date(response.value[i].LastUpdated);
                        response.value[i].Entity = JSON.parse(response.value[i].Json); 
                    }
                    return response.value;
                },
                total: (response) => response.value.length
            }
        });;
    },

      setupComponentGrid: async function (ds, container) {
        var cacheGrid = new GridWidget( container, ds);
        cacheGrid.columns = [
           
            { 
                field: "Entity.Key", 
                title: "[resource_shortdisplayname[key]]",
                width: 200
            },
            { 
                field: "Entity.ResourceKey", 
                title: "[resource_shortdisplayname[resourceKey]]",
                width: 200
            },
            { 
                field: "Name", 
                title: "[resource_shortdisplayname[name]]",
                width: 480
            },
            { 
                field: "LastUpdated", 
                title: "[resource_displayname[lastupdated]]", 
                type: "date", 
                format: "{0: " + type.dateFormat + " HH:mm}", 
				width: "[theme[columns.small]]"
            },
            { 
                field: "LastUpdatedBy", 
                title: "[resource_displayname[lastupdatedby]]", 
				width: "[theme[columns.small]]"  
            }
        ];
        cacheGrid.groupable = false;
        cacheGrid.filterable = true;
        cacheGrid.pageable = true;
        cacheGrid.editable = false;
        cacheGrid.detailTemplate = kendo.template($("[name=componentDetails]", container).html()),
            cacheGrid.detailExpand = function (e) {
                $(e.detailRow).find(".monaco-editor").css("visbility", "visible");
                if ($(e.detailRow).find(".monaco-editor").length === 0) {
                    var component = cacheGrid.dataItem(e.masterRow).Entity;
                    var contentEditor = $(e.detailRow).find("div[name=content]", container.parent());
                    var scriptEditor = $(e.detailRow).find("div[name=script]", container.parent());
                    var html = new HTMLMonacoEditor(contentEditor[0], { code: component.Content });
                    var script = new JavaScriptMonacoEditor(scriptEditor[0], { code: component.Script });
                    html.onChange = (e) => {  component.Content = html.getValue();  };
                    script.onChange = (e) => {  component.Script = script.getValue();  };
                    html.init();
                    script.init();
                }
            };
        cacheGrid.commands.push({ name: "viewVersions", icon: "k-i-clock", text: "[resource_displayname[viewversions]]" });
        cacheGrid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" });
        cacheGrid.commands.push({ name: "remove", icon: "k-i-trash", text: "[resource_displayname[remove]]" });
        cacheGrid.toolbar = "<button class='btn btn-sm btn-primary' name='add'><span class='k-icon k-i-plus'></span> [resource_displayname[add]]</button>";
        cacheGrid.dataBound = function (e) {
            $("[name=viewVersions]", cacheGrid.gridElement).off("click").on("click", (e) => CommonCacheComponents.viewVersions(e, cacheGrid));
            $("[name=save]", cacheGrid.gridElement).off("click").on("click", (e) => CommonCacheComponents.save(e, cacheGrid));
            $("[name=remove]", cacheGrid.gridElement).off("click").on("click", (e) => CommonCacheComponents.removeFromCache(e, cacheGrid));
        };
        await cacheGrid.init();
        $("[name=add]", cacheGrid.gridElement).off("click").on("click", (e) => CommonCacheComponents.newComponent(e, cacheGrid));
        cacheGrid.kendoObject.dataSource.group({ field: "Entity.Key" });
    },

    viewVersions: async function(e, grid) {
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        var versionDialog = new Dialog({title: "[resource_displayname[viewhistory]]", height: 800, width: 1800 });
        versionDialog.init(() => CommonCacheComponents.versionDialogInit(versionDialog, item));
    },

    versionDialogInit: async function(dialog, item) {
        let dataSource = (await api.get("Core/CommonObject?$filter=Type eq 'ContentManagement/Component' and Name eq '" + item.Name + "'&$orderby=Version desc"))
            .value;
        var grid = new GridWidget(dialog.element, {data: dataSource, pageSize: 20 });
        grid.columns = [
            { field: "Version", title: "[resource_displayname[version]]"},
            { field: "LastUpdated", title: "[resource_displayname[lastupdated]]", width: 120, type: "date", format: "{0: " + type.dateFormat + " HH:mm}" },
            { field: "LastUpdatedBy", title: "[resource_displayname[lastupdatedby]]", width: 200 },
        ];
        grid.groupable = false;
        grid.detailTemplate = `<div>
            <div name='contentEditor' style='height:600px; padding-bottom: 40px;  '><h4> [resource_displayname[recentcontentchanges]]</h4></div>
            <div name='scriptEditor' style='height:600px; padding-bottom: 40px; '><h4> [resource_displayname[recentscriptchanges]]</h4></div>
        </div>`;
        grid.detailExpand = function(e) {
            var versionedComponent = JSON.parse(item.Json);
            var originalComponent = JSON.parse(grid.dataItem(e.masterRow).Json);
            var expandContainer = $(e.detailRow);

            var originalContentModel = monaco.editor.createModel(originalComponent.Content, "text/html" );
            var modifiedContentModel = monaco.editor.createModel(versionedComponent.Content, "text/html");

            var diffEditorContent = monaco.editor.createDiffEditor($("[name=contentEditor]", expandContainer)[0], { automaticLayout: true });
            diffEditorContent.setModel({ original: originalContentModel, modified: modifiedContentModel });

            monaco.editor.createDiffNavigator(diffEditorContent, {  followsCaret: true,  ignoreCharChanges: true });

            var originalScriptModel = monaco.editor.createModel(originalComponent.Script, "text/javascript" );
            var modifiedScriptModel = monaco.editor.createModel(versionedComponent.Script, "text/javascript");

            var diffEditorScript = monaco.editor.createDiffEditor($("[name=scriptEditor]", expandContainer)[0], { automaticLayout: true });
            diffEditorScript.setModel({ original: originalScriptModel, modified: modifiedScriptModel });

            monaco.editor.createDiffNavigator(diffEditorScript, {  followsCaret: true,  ignoreCharChanges: true });
        };
        await grid.init();
    },

    save: async function(e, grid) {
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        var dupe = JSON.parse(JSON.stringify(item));
        dupe.Entity.Key = dupe.Key;
        dupe.Json = JSON.stringify(dupe.Entity);
