CommonCacheEndpoint = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=CommonCache]");
        container.addClass("large");

    api.addToMetaCache([{
        "Name": "CommonCache",
        "Types": [
            [meta[Core/CommonObject]],
            [meta[ContentManagement/Component]],
            [meta[Core/Script]],
            [meta[Core/Resource]]
        ]
    }]);

        this.initNavTabIds(container);
        await this.addClickListenerForComponents(container);

        var firstPane = $('.tab-pane.active', container);
        var component = firstPane.attr('data-component');

        if (component) {
            await loadComponent(firstPane, component, async (c) => {
                await c.init(session.app, $(`.component[name=${component}]`, firstPane));
            });
        }

        $("[name=appToolbar]").kendoToolBar({
            items: [
                {
                    type: "button",
                    template: "<button class='btn btn-sm btn-primary' name='refreshCache'><span class='k-icon k-i-arrow-rotate-cw'></span> [resource_displayname[refreshCache]]</button>"
                },
                {
                    type: "button",
                    template: "<button class='btn btn-sm btn-primary' name='migrate' data-bs-toggle='modal' data-bs-target='#common-cache-migrate-modal'><span class='k-icon k-i-arrow-up'></span> [resource_displayname[migrate]]</button>"
                },
                {
                    type: "button",
                    template: "<button class='btn btn-sm btn-primary' name='recentChanges'><span class='k-icon k-i-clock'></span> [resource_displayname[recent]]</button>"
                }
            ]
        });

        $("[name=refreshCache]", container).click(async () => await CommonCacheEndpoint.rebuildCache());
        $("[name=migrate]", container).click(async () => await CommonCacheEndpoint.migrate(app, container));
        $("[name=recentChanges]", container).click(async () => await CommonCacheEndpoint.recentChanges());
    },

    migrate: async function (app) {
        var distinctTypes = await api.get("Core/CommonObject?$apply=groupby((Type))");
        var migrateDialog = new Dialog({ title: "[resource_displayname[migrate]]", width: 620, height: "auto" });
        var targets = app.Config.Deployment.Targets;
        var typeGrid = null;
        migrateDialog.template = $("[name=migrateCommonCacheDialog]").html();
        migrateDialog.events.migrate = async () => {
            var userLogin = { User: session.user, Pass: $("[name=password]", migrateDialog.element).val() };
            CommonCacheEndpoint.doMigration(typeGrid, $("[name=environment]", migrateDialog.element).val(), userLogin, app);
            migrateDialog.events.close();
        };
        migrateDialog.init(async () => {
            typeGrid = await CommonCacheEndpoint.setupCommonTypesGrid(migrateDialog.element, distinctTypes);
            $("[name=environment]", migrateDialog.element).kendoDropDownList(
                { autoBind: false, optionLabel: "[resource_displayname[selectenvironment]]", dataTextField: "EnvironmentName", dataValueField: "EnvironmentName", dataSource: targets }
            );
        });
    },

    doMigration: async function (typeGrid, targetSelected, userLogin, app) {
        notification.info("[resource_displayname[importing]]");
        var typesSelected = typeGrid.select().map(c => c.Type);
        var exportedSet = [];
        for (let i = 0; i < typesSelected.length; i = i + 1) {
            exportedSet.push((await api.get("Core/CommonObject/Latest()?type=" + typesSelected[i])).value);
        }
        var targetApi = app.Config.Deployment.Targets.filter(r => r.EnvironmentName == targetSelected)[0].Api;
        var newApi = new Api({ apiRoot: targetApi });
        await newApi.login(userLogin.User, userLogin.Pass, true);
        await newApi.post("Core/CommonObject/Import", { value: exportedSet.flat() }).then(async () => {
            await newApi.get("RefreshCache");
            notification.success("[resource_displayname[imported]]");
        }).catch((err) => error(err));
    },

    setupCommonTypesGrid: async function (container, dataSource) {
        var grid = new GridWidget($("[name=migrateGrid]", container), dataSource);
        grid.groupable = false;
        grid.pageable = false;
        grid.columns = [
            { selectable: true, width: 40 },
            { field: "Type", title: "[resource_displayname[type]]" }
        ];
        await grid.init();
        return grid;
    },

    recentChanges: async function () {
        var recentDialog = new Dialog({ title: "[resource_displayname[recent]]", width: 1000, height: 800 });
        var recentChangesDataSource = await model.getDatasource({ endpoint: "Core/CommonObject", sort: { field: "CreatedOn", dir: "desc" } })
        recentDialog.template = "<div name='recentGrid' style='width:100%;height:100%;'></div>";
        recentDialog.init(async () => {
            var recentGrid = new GridWidget($("[name=recentGrid]", recentDialog.element), recentChangesDataSource);
            recentGrid.filterable = true;
            recentGrid.editable = false;
            recentGrid.detailTemplate = "<div name='content' style='min-height:400px;'></div>";
            recentGrid.detailExpand = (e) => {
                if (!($(e.detailRow).attr("expanded") === "true")) {
                    $(e.detailRow).attr("expanded", "true");
                    var commonObject = recentGrid.dataItem($(e.masterRow).closest("tr"));
                    var codeBlock = commonObject.Json;
                    var entity = JSON.parse(commonObject.Json);
                    if (commonObject.Type == "Core/Script") { codeBlock = entity.Content; }
                    else if (commonObject.Type == "ContentManagement/Component") { codeBlock = entity.Content + "\n\n" + entity.Script }
                    var editor = new MonacoEditor($("[name=content]", $(e.detailRow))[0], {
                        language: "json",
                        code: codeBlock
                    });
                    editor.init();
                }
            };
            recentGrid.columns = [
                {
                    field: "Name",
                    title: "[resource_displayname[name]]"
                },
                {
                    field: "Type",
                    title: "[resource_displayname[type]]"
                },
                {
                    field: "CreatedBy",
                    title: "[resource_displayname[createdby]]",
                    width: "[theme[columns.small]]"
                },
                {
                    field: "CreatedOn",
                    title: "[resource_displayname[createdon]]",
                    format: "{0: " + type.dateFormat + "}",
                    width: "[theme[columns.small]]"
                },
                {
                    field: "Version",
                    title: "[resource_displayname[version]]"
                }
            ];
            await recentGrid.init();
        });
    },

    initNavTabIds: function (container) {
        var idSuffix = Date.now();

        var nav = $('#common-cache-nav-tab', container);
        nav.attr('id', `${nav.attr('id')}-${idSuffix}`);

        var content = $('#common-cache-nav-tabContent', container);
        content.attr('id', `${content.attr('id')}-${idSuffix}`);

        $('button[role=tab]', nav).each(function () {
            var btn = $(this);
            btn.attr('data-bs-target', `${btn.attr('data-bs-target')}-${idSuffix}`);
        });

        $('.tab-pane', content).each(function () {
            var pane = $(this);
            pane.attr('id', `${pane.attr('id')}-${idSuffix}`);
        });
    },



    addClickListenerForComponents: async function (container) {

        $('button[role=tab]', container).each(function () {

            var button = $(this);

            button.on('shown.bs.tab', async function (e) {

                // 🔥 Use event target instead of re-querying
                var targetSelector = $(e.target).attr('data-bs-target');
                var target = $(targetSelector, container);

                var component = target.attr('data-component');
                if (!component) return;

                var existing = $(`.component[name=${component}]`, target);

                if (existing.length === 0) {
                    await loadComponent(target, component, async (c) => {
                        await c.init(session.app, $(`.component[name=${component}]`, target));
                    });
                }
            });
        });
    },

    rebuildCache: async function () {
        await api.get("RefreshCache").then(() => notification.success("[resource_displayname[rebuilt]]"));
    }
}

