                CreatedOn: (new Date()).toISOString(),
                LastUpdated: (new Date()).toISOString()
            };

            var commonObject = {
                Id: 0,
                Key: script.Key,
                Name: script.Name,
                CreatedOn: script.CreatedOn,
                LastUpdated: script.LastUpdated,
                Json: JSON.stringify(script),
                Type: "Core/Script",
                Culture: "",
                Version: 1
