    },

    versionDialogInit: async function (dialog, item) {
        let dataSource = (await api.get(
            "Core/CommonObject?$filter=Type eq 'Core/Script' and Name eq '" + item.Name + "'&$orderby=Version desc"
        )).value;

        var grid = new GridWidget(dialog.element, { data: dataSource, pageSize: 20 });
        grid.columns = [
            { field: "Version", title: "[resource_displayname[version]]" },
            { field: "LastUpdated", title: "[resource_displayname[lastupdated]]", width: 120, type: "date", format: "{0: " + type.dateFormat + " HH:mm}" },
            { field: "LastUpdatedBy", title: "[resource_displayname[lastupdatedby]]", width: 200 }
        ];

        grid.groupable = false;
        grid.detailTemplate = `<div style='height:600px; padding-bottom: 40px;'>
            <div name='scriptEditor'><h4>[resource_displayname[recentscriptchanges]]</h4></div>
        </div>`;

        grid.detailExpand = function (e) {
            var versionedScript = JSON.parse(item.Json);
            var originalScript = JSON.parse(grid.dataItem(e.masterRow).Json);
            var expandContainer = $(e.detailRow);

            var originalScriptModel = monaco.editor.createModel(originalScript.Content, "text/javascript");
            var modifiedScriptModel = monaco.editor.createModel(versionedScript.Content, "text/javascript");

            var diffEditorScript = monaco.editor.createDiffEditor(
                $("[name=scriptEditor]", expandContainer)[0],
                { automaticLayout: true }
            );

            diffEditorScript.setModel({ original: originalScriptModel, modified: modifiedScriptModel });

            monaco.editor.createDiffNavigator(diffEditorScript, { followsCaret: true, ignoreCharChanges: true });
        };


        await grid.init();
    }
};

