      var folder = tree.dataItem(node).data;
      var inputElement = $("<input id = 'file' type='file' style='visibility: hidden; position: absolute'/>").appendTo(container);
      $(inputElement).change(async (e) => {
        api.file.upload(folder.Path + "?unpack",$(inputElement)[0].files[0], () => {
            notification.success("[resource_displayname[unpacked]]");
        });

      });
      document.getElementById("file").click();
    },

    renameFolder: async function (e, tree, node) {
        e.preventDefault();
        var data = tree.dataItem(node).data;

        var editorDialog = new EditorDialog({
            title: "[resource_displayname[renamefolder]]",
            fields: [ { field: "Name", title: "[resource_displayname[name]]" }],
            confirm: "[resource_displayname[update]]",
            data: data
        });

        editorDialog.events.confirm = (e) => {
            editorDialog.data.save(e);
            tree.text(node, data.Name)
            editorDialog.events.close();
        };

        await editorDialog.init();
    },

    addNewFolder: async function (e, app, tree, node) {
        e.preventDefault();

        var folder = await model.item.createInstance("Core/Folder");
        folder.AppId = app.Id;

        var hasParent = node.length > 0 && !$(node).hasClass("k-treeview");

        if(hasParent) {
            var item = tree.dataItem(node).data;
            folder.ParentId = item.Id;
        }

        var editorDialog = new EditorDialog({
            title: "[resource_displayname[newfolder]]",
            confirm: "<span class='k-icon k-i-plus'></span> [resource_displayname[create]]",
            fields: [
                { field: "Name", title: "[resource_displayname[name]]" }
            ],
            data: folder
        });

        editorDialog.events.confirm = async (e) => {
            await editorDialog.data.save(e);
            if(hasParent) {
                var item = tree.dataItem(node);
                if(item.expanded) {
                    tree.collapseNode(node);
                    tree.expandNode(node);
                 }
            } else {
                await tree.refresh();
            }
            editorDialog.events.close();
        };

        editorDialog.init();
    },

    removeFolder: async function (e, tree, node) {
        var data = tree.dataItem(node).data;

        var c = new ConfirmDialog({
            title: "[resource_displayname[DeleteFolderTitle]]: " + data.Path,
            question: "[resource_displayname[deleteconfirmation]]",
            confirm: "[resource_displayname[confirm]]",
            close: "[resource_displayname[close]]"
        });

        c.events.confirm = async function () {
            await data.destroy(e);
            notification.success('[resource_description[FolderDeletedSuccesfully]]');
            tree.removeNode(node);
            c.events.close();
        };
        c.init();
    },

