FlowInstanceDetails = {
	init: async function (app, container, instance, reportComponent) {
		app = app || session.app;
		container = container || $(".component[name=FlowInstanceDetails]");
		if(!instance)
            return;

        var id = FlowInstanceDetails.initNavTabIds(app, container);

		if (instance.State !== "Executing") {
			if (!reportComponent) {
				$(`#flow-instance-details-report-tab-${id}`, container).hide();
			}

			await api.get("Workflow/FlowInstanceData(" + instance.Id + ")").then(function (i) {
				if (reportComponent) {
					var reportTab = $("[name=report]", container);
					loadComponent(reportTab, reportComponent, function (c) {
                        window[reportComponent].init(app, reportTab, i);
                    });
				}
				if (i.ContextString) {
					var details = JSON.parse(i.ContextString);
					FlowInstanceDetails.initLog(app, $("[name=log]", container), details.ExecutionLog);
					FlowInstanceDetails.initFlow(details, $("[name=flow] > .flow", container));
					for (var v in details.Variables) {
						var item = "<li><label>" + v + "</label><div class='value'>" + details.Variables[v] + "</div></li>";

						if (item.includes("[object Object]")) {
							item = "<li><label>" + v + "</label><div class='value'>";
							item += "<textarea name='" + v + "'>" + JSON.stringify(details.Variables[v], null, 4) + "</textarea>";
							item += "</div></li>";
						}

						$("[name=variables]", container).append(item);
					}
				}
			}).catch((err) => {
				notification.error(err);
			});
		} else {
            // If the workflow is executing, connect to it.
			await FlowInstanceDetails.connectToWorkflow(app, container,container, instance, reportComponent);
		}
	},

    initNavTabIds: function(app, container) {
        var id = Guid();
        var template = $('script[name=flow-instance-details-tabs]', container).html();
        template = template.replaceAll('{ID}', id);

        container.append(template);

		return id;
    },

	connectToHub: async function(console, callback, completeCallback) {
		var connection = new signalR.HubConnectionBuilder().withUrl(session.apiRoot + "Hubs/Workflow").build();
		connection.on("ConsoleReceive", function (level, message, instance) {
			var d = new Date();
			var time = d.getHours() + ":" + d.getMinutes() + ":" + d.getSeconds();
			var logHtml = FlowInstanceDetails.buildMessage({
				Level: level,
				Timestamp: new Date(),
				Message: message
			});
			$(".execConsole > [name=flowConsole]", console).append(logHtml);
			if (level == "info" && message == "Done!") {
				connection.invoke("leave", instance);
				notification.info("Disconnected from workflow hub.");
				if (completeCallback)
                    completeCallback(instance, console, connection);
			}
		});
		await connection.start();
		callback(console, connection);
	},

	connectToWorkflow: async function (app, container, console, instanceData, reportComponent) {
		await FlowInstanceDetails.connectToHub(console, (console, connection) => {
			connection.invoke("join", instanceData.Id);
			connection.invoke("ConsoleSend", "info", "Client Connected to instance " + instanceData.Id, instanceData.Id);
		}, async (finalInstanceData,cconsole,connection) => {
			await FlowInstanceDetails.init(app, container, finalInstanceData, reportComponent);
		});
	},

	initLog: function (app, container, log) {
		var entries = log.map(i => FlowInstanceDetails.buildMessage(i));
		$(".execConsole > [name=flowConsole]", container).append(entries);
	},

	initFlow: function (instance, container) {
		var executionOrder = instance.ExecutionLog
			.filter(l => l.Message.indexOf("::") !== -1 && l.Message.endsWith("Activity Execution started"))
			.map(l => l.Message.split(":")[0]);

		executionOrder.map(ex => {
			var activity = instance.Flow.Activities.filter(a => a.Ref === ex)[0];
			var log = instance.ExecutionLog.filter(l => l.Message.startsWith(activity.Ref + "::"));
			FlowInstanceDetails.initActivity(container, instance.Flow, activity, log);
		});

		$(".activity > .in > ").on("hover", function (a) {
			$(".tip[name=" + $(a).attr("name") + "]").css("display", "block");
		});
	},

	initActivity: function (container, flow, activity, log) {
		var aRef = activity.Ref.replaceAll(' ', '').replaceAll("'", "");
		var links = flow.Links.filter(l => l.Source === activity.Ref);
		var linkCode = links.map(l => l.Expression).join("\n");

		var element =
			"<div name='" + aRef + "' class='activity state-" + activity.State + "'>" +
			"<h4><span class='k-icon k-i-gears'></span>" + activity.Ref + "</h4><div class='in'>" +
			"<a href='' class='state'><span class='k-icon k-i-css'></span>View State</a>" +
			"<a href='' class='log'><span class='k-icon k-i-txt'></span>View Log</a>" +
			"</div></div><div class='sep'><span class='k-icon k-i-forward'></span></div>";

		container.append(element);

		var console = "<div name='" + aRef + "'>" +
			"<div class='execConsole' name='execConsole'>" +
			"<div class='console' name='flowConsole'>";

		log.map(i => console += FlowInstanceDetails.buildMessage(i));

		console += " </div></div></div>";

		$(document.body).append($("<div name='" + aRef + "State'><textarea class='activityJson'>" + JSON.stringify(activity, null, 4) + "</textarea></div>"));
		var dialog1 = $("[name='" + aRef + "State']");
		var d1 = dialog1.kendoWindow({
			visible: false,
			modal: true,
			resizable: false,
			width: 800,
			height: 700,
			title: "[resource_displayname[AcitvityLog]]"
		}).data("kendoWindow");

		$(".activity[name=" + aRef + "] a.state").on("click", function (e) {
			e.preventDefault();
			d1.center().open();
		});

		$(document.body).append($("<div name='" + aRef + "Log'>" + console + "</div>"));
		var dialog2 = $("[name='" + aRef + "Log']");
		var d2 = dialog2.kendoWindow({
			visible: false,
			modal: true,
			resizable: false,
			width: 800,
			height: 700,
			title: "[resource_displayname[AcitvityLog]]"
		}).data("kendoWindow");

		$(".activity[name=" + aRef + "] a.log").on("click", function (e) {
			e.preventDefault();
			d2.center().open();
		});
	},

	buildMessage: function (logEntry) {
		var time = new Date(logEntry.Timestamp);
		return "<div class='message " + logEntry.Level.toLowerCase() + "'>" +
			"<span class='time'>" + time.getHours() + ":" + time.getMinutes() + ":" + time.getSeconds() + "</span>" +
			"<pre class='message'>" + html.encode(logEntry.Message) + "</pre>" +
			"</div>";
	}
}

FlowInstanceManagement = {
    states: {
        "Not Run": "[resource_displayname[notrun]]",
        "Executing": "[resource_displayname[executing]]",
        "Complete": "[resource_displayname[complete]]",
        "Suspended": "[resource_displayname[suspended]]",
        "Queued": "[resource_displayname[queued]]",
