    },

    init: async function (app, container, definitionId, reportComponentName) {
        app = app || session.app;
        container = container || $('.component[name=FlowInstanceManagement]');

        if(!definitionId)
            return;

        api.addToMetaCache([
            {
                "Name": "Core",
                "Types": [
                    [meta[Workflow/FlowInstanceData]]
                ]
            }
        ]);
        var config = {
            endpoint: "Workflow/FlowInstanceData",
            odataAppend: "?$filter=FlowDefinitionId eq " + definitionId + "&$select=Id,Name,State,Start,End,Caller",
            pageSize: 20
        };
        var ds = await model.getDatasource(config);
        var grid = new GridWidget(container, ds);
        grid.toolbar = "<button class='btn btn-sm btn-primary' name='deleteAll'><span class='k-icon k-i-trash'></span>[resource_displayname[deleteall]]</button>";
        grid.scrollable = false;
        grid.columns = [
            { field: "Id", title: "[resource_displayname[id]]" },
            { field: "State", title: "[resource_displayname[state]]", template: "#=FlowInstanceManagement.states[State]#"},
            { field: "Caller", title: "[resource_displayname[caller]]" },
            { field: "Start", width: 130, format: "{0:" + type.dateFormat + " HH:mm}", title: "[resource_displayname[start]]" },
            { field: "End", width: 130, format: "{0:" + type.dateFormat + " HH:mm}", title: "[resource_displayname[end]]" },
        ];
        grid.commands.push({name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]"});
        grid.dataBound = function (e) {
            $('[name=delete]', grid.gridElement).off("click").on("click", async (e) => await FlowInstanceManagement.deleteInstance(e, grid));
        };
        grid.detailTemplate = "<div name='details'></div>";
        grid.detailExpand = function (e) {
            var instance = grid.dataItem(e.masterRow);
            if ($("[name=details]", e.detailRow)[0].childElementCount === 0) {
                var subContainer = $("[name=details]", e.detailRow);
                subContainer.html($("[name=flowInstanceDetailsComponent]").first().html());
                FlowInstanceDetails.init(app, $(".component[name=FlowInstanceDetails]", subContainer), instance, reportComponentName);
            }
        };
        grid.groupable = false;
        await grid.init();
        grid.kendoObject.dataSource.sort({field: "Start", dir: "desc"});
        $("[name=deleteAll]", grid.gridElement).on("click", async (e) => FlowInstanceManagement.deleteAll(e, definitionId, grid));
    },

    deleteAll: async function(e, definitionId, grid) {
        e.preventDefault();
        notification.info("[resource_displayname[deleting]]");
        await api.get("Workflow/FlowInstanceData?$filter=FlowDefinitionId eq " + definitionId+"&$select=Id").then(async (data) => {
            var flowInstances = data.value.map(c => c.Id);

            for(var i in flowInstances)
                await api.destroy('Workflow/FlowInstanceData(' + flowInstances[i] + ')');

            notification.success("[resource_displayname[deleted]]");
            grid.refresh();
        });
    },

    deleteInstance: async function (e, grid) {
        var row = $(e.target).closest('tr');
        var item = grid.dataItem(row);
        await item.destroy(e).then(() => {
            notification.success("[resource_description[deleted]]");
            grid.refresh();
        });
    }
}

