		var grid = $("[name=grid]", root).data("kendoGrid");
        var theForm = grid.dataItem($(e.currentTarget).closest("tr"));
        theForm.save(e, function () {
            notification.success("[resource_description[FormSaved]]");
        });
    },

    destroy: function (e) {
        e.preventDefault();
		var root = $(".component[name=Forms]");
		var grid = $("[name=grid]", root).data("kendoGrid");
        var theForm = grid.dataItem($(e.currentTarget).closest("tr"));
        theForm.destroy(e, function () {
            notification.success("[resource_description[FormDeleted]]");
            var grid = $(".component[name=Forms] [name=grid]").data("kendoGrid");
            grid.dataSource.read();
            grid.refresh();
        });
    }
};

