GridBuilder = {
	init:function(app, container) {
      app = app || session.app;
      container = container || $('.component[name=GridBuilder]');
      $('[name=tabstrip]', container).kendoTabStrip({
		activate:function(e){
			if($(e.item).attr('name') === 'preview') {
				GridBuilder.showgridView(container);
			}
		}
	});

		GridBuilder.filterable = true;
		GridBuilder.GridName = '';

		GridBuilder.root = $('[name="GBWizard"].component');
		// go get a list of endpoints from api
		api.get('', function(endpoints){
			var endpointDD = $('[name=endpoints]', GridBuilder.root);

			// create a drop down with a change event
			endpointDD.kendoDropDownList({
				dataSource: endpoints.value,
				dataTextField:'name',
				dataValueField: 'url',
				change: GridBuilder.endpointChange
			});

			// select first and trigger change event
			endpointDD.data('kendoDropDownList').select(0);
			endpointDD.data('kendoDropDownList').trigger('change');

			// set filterable flag
			$('[name=filterable]', GridBuilder.root).off('click').on('click', function(){
				GridBuilder.filterable = this.checked;
			});

			// set gridname
			$('[name=gridname]', GridBuilder.root).off('keyup').on('keyup', function(){
				GridBuilder.GridName = this.value;
			});
		})
	},

	setupFilters:function(){		
		var root = $('[name=tbfilters]');

		GridBuilder.checkOld($('[name=grid]', root));

		$('[name=grid]', root).kendoGrid({
			toolbar:'<button class="btn" name="add">Add New Filter</button>',
			dataSource:[],
			editable:true,
			columns:[
				{ field: 'field' , editor: GridBuilder.fieldEditor },
				{ field: 'operator', editor: GridBuilder.operatorEditor },
				{ field: 'value', editor: GridBuilder.valueEditor },
				{ template: '<span class="k-icon k-i-close-circle" name="delete"></span>', width:25 }
			],
			dataBound:function(e){
				var grid = e.sender.element;
				$('[name=add]', grid).off('click').on('click', {grid: grid}, GridBuilder.addFilter);
				$('[name=delete]', grid).off('click').on('click', {grid: grid}, GridBuilder.removeFilter);
			}
		});

		GridBuilder.setUpactions(root);		
	},

   	setUpactions: function(root){
		GridBuilder.checkOld($('[name=actionGrid]', root));

		var actions = [
			{ 
				name: 'dataBound', 
				code: `var grid = e.sender.element; 
$('.clx-loader', grid.parent()).hide(); 
$('.k-grid-content', grid).css('max-height', (window.innerHeight * 0.7) + 'px');

$('[name=export]', grid).off('click').on('click', function(ev){
	kendo.ui.progress(grid, true);

	var columns = e.sender.columns;
	var url = unescape(e.sender.dataSource.lastGet.url);
	url = url.replace(/\\&\\$top=\d+/g, '').replace(/\\?\\$top=\d+/g, '');
	exportData.byQuery(url).toExcel(columns,"[GRIDNAME]", function(){ kendo.ui.progress(grid, false); });
});` 
			}		
		];

		$('[name=actionGrid]', root).kendoGrid({
			toolbar:'<button class="btn" name="add">Add New Action</button>',
			dataSource:actions,
			editable:true,
			columns:[
				{ field: 'name' }
			],
			detailTemplate: kendo.template('function(e){<br/><textarea data-bind="value: code">#:code#</textarea><br/>}'),
			detailExpand:function(e){
				var di = this.dataItem(e.masterRow);
				if(e.detailRow.find('.CodeMirror').length === 0){
					e.detailRow.css('background', '#cbcbcb');

					var f = CodeMirror.fromTextArea($('textarea', e.detailCell)[0],  { tabsize: 3, indentUnit: 3, mode: 'javascript' });
					f.on("change", function() { 
						di.code= f.getValue(); 
					});
				}
			},
			dataBound:function(e){
				$('[name=add]', e.sender.element).off('click').on('click', function(){
					e.sender.dataSource.add({
						name:'new',
						code:''
					});
				})
			}
		});	
	},

	addFilter:function(e){
		e.data.grid.data('kendoGrid').dataSource.add({
			field:GridBuilder.fields[0].name,
			operator:'eq',
			value:'',
			type: GridBuilder.fields[0].type
		});	

		GridBuilder.updateFilters();
	},

	fieldEditor:function(container, options){
		$('<input name="' + options.field + '" data-bind="value:' + options.field + '"/>')
			.appendTo(container)
			.kendoDropDownList({
				dataSource: GridBuilder.fields,
				dataTextField:'name',
				dataValueField:'name',
				change:function(e){
					options.model.type = this.dataItem().type;
					GridBuilder.updateFilters();
				}
			});
	},

	valueEditor:function(container, options){
		var input = $('<input name="' + options.field + '" data-bind="value:' + options.field + '"/>').appendTo(container);

		if(options.model.type.toLowerCase().indexOf('date') > -1){
			input.kendoDateTimePicker();
		}
	},

	operatorEditor:function(container, options){
		$('<input name="' + options.field + '" data-bind="value:' + options.field + '"/>')
			.appendTo(container)
			.kendoDropDownList({
				dataSource:[ 
					{ id:'eq', name: 'Equals' }, 
					{ id: 'ne', name: 'Not'}, 
					{ id: 'gt', name:'Greater than' }, 
					{ id: 'lt', name:'Less than' }, 
					{ id: 'gte', name:'Greater than or equal to' }, 
					{ id: 'lte', name:'Less than or equal to' }, 
					{ id: 'contains', name:'Contains' }, 
					{ id: 'startswith', name:'Starts with' }
				],
				dataTextField:'name',
				dataValueField:'id'
			});
	},

	removeFilter:function(e){
		var row = $(e.target).closest('tr');
		var di = e.data.grid.data('kendoGrid').dataItem(row);

		e.data.grid.data('kendoGrid').dataSource.remove(di);
		GridBuilder.updateFilters();
	},

	showgridView:function(e){
		// get the query and load in content for displaying grids
		var query = GridBuilder.generateQuery();

		var viewRoot = $('[name=tbpreview]');

		GridBuilder.checkOld($('[name=grid]', viewRoot));

		$('[name=save]', viewRoot).off('click').on('click', {root: viewRoot},GridBuilder.saveGrid);

		// build final grid
		GridBuilder.buildGrid(viewRoot, query);	
	},

	// save the grid out as a component
	saveGrid:function(e){
		if(GridBuilder.GridName){
			api.add('ContentManagement/Component', {
				Id:0,
				AppId: session.app.Id,
				Name: GridBuilder.GridName.replace(/ /g, ''),
				ResourceKey: 'Component/' + GridBuilder.GridName.replace(/ /g, ''),
				Content:'',
				Script: GridBuilder.config,
				Category:'Grid'
			}, function(res){
				notification.success('Grid Component successfully added');
			});
		}	
		else{
			notification.error('Grid must be given a name in order to save');
		}
	},

	buildGrid:function(root, query){
		window[GridBuilder.GridName] = {};		

		if(GridBuilder.GridName){
			$('[name=fullQuery]', root).text(query.full);

			var toolbar = $('[name=toolbar]', root.parent()).val() || null; // if we have defined a toolbar we want to use it
			var actions = $('[name=actionGrid]', root.parent()).data('kendoGrid').dataSource.data();

			actions.map(function(a){
				window[GridBuilder.GridName][a.name] = new Function("e", a.code.replace('[GRIDNAME]', GridBuilder.GridName.replace(/ /g, '')));
			});

			// define the config for model.dataSource
			var config = {
				endpoint: query.base,
				odataAppend: query.append,
				filter: { logic:'and', filters: GridBuilder.filters },
				group: GridBuilder.selects.filter(GridBuilder.isGrouped).sort(function(a,b){ return a.order - b.order }).map(function(d){ return { field: d.name } }),
				sort: GridBuilder.selects.filter(GridBuilder.isSorted).sort(function(a,b){ return a.order - b.order }).map(function(d){ return { field: d.name , dir: 'desc'} }),
			};

			// build the grid and see that it works
			model.getDatasource(config, function(ds){
				root.prepend('<div class="clx-loader"></div>');

				// config for grid
				$('[name=grid]', root).kendoGrid({
					toolbar: '<button name="export"><span class="k-icon k-i-excel"></span>  [resource_displayname[ExportToExcel]]</button>' + (toolbar || (GridBuilder.GridName ? '<h3>'+GridBuilder.GridName+'</h3>' : null)), // if we define a toolbar use, else try use grid name, else null
					dataSource:ds,
					columns: GridBuilder.columnfy(GridBuilder.selects), // turn our selects into columns
					pageable: true,
					filterable: GridBuilder.filterable,
					sortable:true,
					dataBound:(window[GridBuilder.GridName] || {}).dataBound || function(e){
						// remove the loading thing
						$('.clx-loader', root).remove();
					}
				});
			});		

			GridBuilder.buildConfig(config);
		}
		else{
			notification.error('Please give a name to your grid');
		}
	},

	buildConfig:function(config){
		var name = GridBuilder.GridName.replace(/ /g, '');
		var actions = $('[name=actionGrid]').data('kendoGrid').dataSource.data();
		var databound = actions.filter(function(a){ return a.name === 'dataBound'})[0].code
		var toolbar = $('[name=toolbar]').val() || null; // if we have defined a toolbar we want to use it

		GridBuilder.config =(
			`${name} = {
				init:function(){
					var root = $("[name=${name}].component");
					var grid = $("<div></div>").appendTo(root);
					grid.prepend("<div class='clx-loader'></div>");

					model.getDatasource(${JSON.stringify(config)}, function(ds){
						grid.kendoGrid({
							toolbar: '${'<button name="export"><span class="k-icon k-i-excel"></span>  [resource_displayname[ExportToExcel]]</button>' +  (toolbar || (GridBuilder.GridName ? '<h3>'+GridBuilder.GridName+'</h3>' : null))}',
							dataSource:ds,
							columns: ${JSON.stringify(GridBuilder.columnfy(GridBuilder.selects, true))},
							pageable:true,
							sortable:true,
							filterable: ${GridBuilder.filterable},
							dataBound:function(e){
								${databound.replace('[GRIDNAME]', name)}
							}
						});

						root.kendoTooltip({
							filter:'th',
							position: "top",
							content:function(e){
								var target = e.target;
								if($(target).text()){
									e.sender.popup.element.css("visibility", "visible");
									return $(target).text();
								}
								else{					
									e.sender.popup.element.css("visibility", "hidden");
								}
							}
						});
					});
				}
				${actions.filter(function(a){ return a.name !== 'dataBound'}).map(function(a){
					return `,${a.name}:function(e){
						${a.code.replace('[GRIDNAME]', name)}
					}`
				}).join('')}
			};
			$(function(){ 
				${name}.init()
			})`
		);
	},

	// turn a meta property into a column
	columnfy:function(cols, forConfig){
		cols = cols.sort(function(a,b){ return parseInt(a.order) - parseInt(b.order) });

		var columns = cols.map(function(col){ 
			return {
				field: col.name,
				headerTemplate: (forConfig && col.title.trim()) ? '<span data-resource="'+col.title+'" >[resource_shortdisplayname['+col.title+']]</span>' : null,
				template: col.template,
				attributes: col.attributes ? col.attributes : null,
				title: col.title,
				width: col.width,
				hidden: col.hidden
			}
	 	});		

		return columns;
	},

	generateQuery:function(){
		// make sure we have latest
		GridBuilder.updateSelects();
		GridBuilder.updateExpands();
		GridBuilder.updateFilters();

		// identify the sections that will make up final query
		var base = GridBuilder.endpoint + '/' + GridBuilder.context;
		var selects = GridBuilder.selects.filter(function(s){ return s.name }).map(function(s){ return s.name }).join(',');
		var expands = GridBuilder.expandQuery();
		var odataAppend = (selects ? ('?$select=' + selects) : '') + ( selects && expands ? '&' : ( expands ? '?' : '' ) ) + (expands ? ('$expand=' + expands) : '');

		var query = base + odataAppend;
		// return object with all info available
		return{
			base: base,
			append: odataAppend,
			full: query
		};
	},

	expandQuery:function(query, expands){
		var exquery = '';
		var selquery = '';

		query = query || '';
		// get list of expands relevant
		expands = (expands || GridBuilder.expands) || [];

		expands.map(function(ex){
			// field will be needed no matter what
			query += ex.field;

			if(ex.selects){
				// selects is just a string list
				selquery = ex.selects.map(function(s){ return s.name }).join(',');
			}
			if(ex.expands){
				// if we have expands within this one then recursively build the string
				exquery =  GridBuilder.expandQuery('', ex.expands);
			}

			if(selquery || exquery){
				// generate final query
				query += '(' + (selquery ? ('$select=' + selquery + ';') : "") + (exquery ? ('$expand=' + exquery + "" ): "") + '),';
			}
			else{
				query += ',';
			}
		});

		if(query[query.length -1] === ","){
			query = query.substring(0, query.length - 1);
		}

		return query;
	},

	endpointChange:function(e){
		// define endpoint
		GridBuilder.endpoint = endpoint = e.sender.value(); 

		var contextsDD = $('[name=contexts]', GridBuilder.root);

		// get a list of contexts from this endpoint
		api.get(endpoint, function(contexts){
			// create a drop down with a change event
			contextsDD.kendoDropDownList({
				dataSource: contexts.value,
				dataTextField:'name',
				dataValueField: 'url',
				change: GridBuilder.contextChange
			});

			// select first and trigger change event
			contextsDD.data('kendoDropDownList').select(0);
			contextsDD.data('kendoDropDownList').trigger('change');
		});
	},

	contextChange:function(e){
		// define context
		GridBuilder.context = context = e.sender.value(); 
		GridBuilder.setupFilters();
		// get meta data for endpoint/context
		api.get(GridBuilder.endpoint + '/' + context + '/GetMetadata', function(meta){
			var selectsGrid = $('[name=selects] > [name=grid]', GridBuilder.root);
			var expandsGrid = $('[name=expands] > [name=grid]', GridBuilder.root);

			// format the properties
			var props = meta.Properties.map(GridBuilder.formatProperty);
			GridBuilder.fields = props;
			// build grids
			GridBuilder.setSelects(selectsGrid, props.filter(GridBuilder.isScalar));
			GridBuilder.setExpands(expandsGrid, props.filter(GridBuilder.notScalar));

			$('body').kendoTooltip({
				filter:'th',
				position: "top",
				content:function(e){
					var target = e.target;
					if($(target).text()){
						e.sender.popup.element.css("visibility", "visible");
						return $(target).text();
					}
					else{					
						e.sender.popup.element.css("visibility", "hidden");
					}
				}
			});
		});
	},

	formatProperty:function(prop){
		var scalar = type.ofProperty.isScalar(prop);

		// reformat before grid
		return {
			name: prop.Name,
			templateType:'',
			title: prop.Name,
			type: prop.ServerType,
			isScalar: scalar,
			// auto select all scalar properties
			selected: false,
			template:'#: '+prop.Name+' #',
			order:0,
			width:'auto',
			group:false,
			sort:false,
			hidden: false,
		};
	},

	formatChildProperty:function(prop){
		// reformat from grid
		return {
			name: prop.name,
			templateType:'',
			title:prop.title,
			selected: prop.selected,
			isScalar: prop.isScalar,
			template: prop.template,
			type: prop.type,
			order: prop.order,
			width:prop.width,
			group: prop.group,
			sort: prop.sort,
			hidden: prop.hidden
		};
	},

	// return if property is scalar
	isScalar:function(item){ return item.isScalar },

	// return if property is not scalar
	notScalar:function(item){ return !item.isScalar },

	isGrouped: function(item){ return item.group },

	isSorted: function(item){ return item.sort },

	// return if property is selected
	isSelected:function(item){ return item.selected },

	// check to see if kendo grid is defined on object and if so destroy
	checkOld:function(grid){
		if(grid.data('kendoGrid')){ 
			grid.data('kendoGrid').destroy();
			grid.empty();
		}
	},

	setExpands:function(grid, data){	
		GridBuilder.checkOld(grid);
		// build kendo grid for expands grid
		grid.kendoGrid({
			dataSource: data,
			editable: true,
			columns:[
				{ template: '<input type="checkbox" #: selected ? "checked" : "" # />', width:25 },
				{ field: 'name' }
			],
			dataBound: GridBuilder.onBind,
			detailInit: GridBuilder.detail
		});
	},

	DefaultEditor:function(con, op){
		// deafult editor(inline)
		var input = $('<input type="text" class="k-input k-textbox" name="'+op.field+'" data-bind="value:'+op.field+'">'); 
		input.appendTo(con); 
	},

	DisabledEditor:function(con, op){
		con.append( '<span style="padding:0 .3em">' + op.model[op.field] + '</span>');
	},

	setSelects:function(grid, data){
		// the only time we want them all selected is on this grid
		data.map(function(d, i){ d.order = i; d.selected = true; return d; });

		GridBuilder.checkOld(grid);
		// build kendo grid for selects grid
		grid.kendoGrid({
			toolbar:'<button class="btn" name="add">Add Custom Column</button>',
			dataSource: {
				data: data,
				sort:{ field:'order', dir:'asc' }
			},
			editable: true,
			save:function(e){ grid.data('kendoGrid').refresh(); },
			columns:[
				{ field: 'order', width: 50 },
				{ template: '<input class="chkSelected" type="checkbox" #: selected ? "checked" : "" # />', width:100 , headerTemplate: '<input type="checkbox" name="checkall" checked/> Select'},
				{ title:'Group', template: '<input class="chkGrouped" type="checkbox" #: group ? "checked" : "" # #: name ? "" : "disabled" #/>', width:50 },
				{ title:'Sort', template: '<input class="chkSort" type="checkbox" #: sort ? "checked" : "" # #: name ? "" : "disabled" #/>', width:50 },
				{ title:'Hide', template: '<input class="chkHidden" type="checkbox" #: hidden ? "checked" : "" # #: name ? "" : "disabled" #/>', width:50 },
				{ field: 'name', editor: GridBuilder.DisabledEditor, template:'#: name ? name : "Custom" #' },
				{ field: 'title', editor: GridBuilder.DefaultEditor },
				{ 
					field: 'template', 
					editor: function(con,op){ 
						// we need a custom editor so someone can only edit this when custome is selected
						op.model.templateType !== 'date' ? GridBuilder.DefaultEditor(con, op) : GridBuilder.DisabledEditor(con, op);
					}
				},
				// create custom template checkboxes
				{ field:'width' },
				{ width:50, title:'Date', template: '<input type="radio" name="#:name#_template" value="Date" #: GridBuilder.checkTemplatetype(templateType, "date") # />' },
				{ width:50, title:'Currency', template: '<input type="radio" name="#:name#_template" value="Currency" #: GridBuilder.checkTemplatetype(templateType, "currency") # />' },
				{ width:50, title:'Number', template: '<input type="radio" name="#:name#_template" value="Number" #: GridBuilder.checkTemplatetype(templateType, "number") # />' },
				{ width:50, title:'Custom', template: '<input type="radio" name="#:name#_template" value="Custom" #: GridBuilder.checkTemplatetype(templateType, "") # />' }
			],
			dataBound: GridBuilder.onBind
		});
	},

	checkTemplatetype:function(type, target){
		// check wether we need to check this item
		return type === target ? 'checked' : '';
	},

	handleRadio:function(e){
		// whena  radio button is checked we need to change the template
		var row = $(e.target).closest('tr');
		var dataitem = e.data.grid.data('kendoGrid').dataItem(row);

		// get the type 
		var type = $(e.target).attr('value');
		dataitem.attributes = {};
		// set dataitem template and template type dependent on type
		switch(type){
			case 'Date':
				dataitem.template = "#:kendo.toString(new Date("+dataitem.name+"),'dd/MM/yyyy')#";
				dataitem.templateType = "date";
			break;
			case 'Currency':
				dataitem.template = "#:my.formatCurrency("+dataitem.name+")#";
				dataitem.attributes = {'style' : 'text-align: right;' };
				dataitem.templateType = "currency";
			break;
			case 'Number':
				dataitem.templateType = "number";
				dataitem.attributes = {'style' : 'text-align: right;' };
			break;
			case 'Custom':
				dataitem.template = "#:"+dataitem.name+"#";
				dataitem.templateType = "";
			break;
		};

		// refresh grid and selects
		e.data.grid.data('kendoGrid').refresh();
		GridBuilder.updateSelects();
	},

	handleCheck:function(e){
		var row = $(e.target).closest('tr');
		var dataitem = e.data.grid.data('kendoGrid').dataItem(row);

		dataitem.selected = this.checked;

		// empty expands and selects
		GridBuilder.expands = [];
		GridBuilder.selects = [];
		// update all selects and expands
		GridBuilder.updateSelects();
		GridBuilder.updateExpands(e.data.grid);
	},

	handleGroupCheck:function(e){
		var row = $(e.target).closest('tr');
		var dataitem = e.data.grid.data('kendoGrid').dataItem(row);

		dataitem.group = this.checked;
	},

	handleSortCheck:function(e){
		var row = $(e.target).closest('tr');
		var dataitem = e.data.grid.data('kendoGrid').dataItem(row);

		dataitem.sort = this.checked;
	},

	handleHiddenCheck:function(e){
		var row = $(e.target).closest('tr');
		var dataitem = e.data.grid.data('kendoGrid').dataItem(row);

		dataitem.hidden = this.checked;
	},

	detail:function(e){
		e.data.id = e.data.id || e.data.name;

		// get meta data value for expanded item
		debugger;
		var ctx = e.data.type.split(',')[0].split('.');
		ctx = ctx[ctx.length - 1];

		api.get(GridBuilder.endpoint + '/' + ctx + '/GetMetadata()', function(meta){
			var data = meta.Properties.map(GridBuilder.formatProperty);

			data.map(function(d){ d.id = e.data.id + '/' + d.name; return d; });

			var grid = $('<div></div>').appendTo(e.detailCell);
			// build expands grid
			GridBuilder.setExpands(grid, data);
		})
	},

	updateSelects:function(){
		// selects are just all items selected in selects grid		
		GridBuilder.selects = $('[name=selects] [name=grid]').data('kendoGrid').dataSource.data().toJSON().filter(GridBuilder.isSelected);	
	},

	updateExpands:function(grid){
		var end_data = [];
		var grids = $('[name=expands] .k-grid').get();

		// get a list of all data from all expand grids
		for(var i = 0; i < grids.length; i++){
			var data = $(grids[i]).data('kendoGrid').dataSource.data().filter(GridBuilder.isSelected);
			end_data.push(data)
		}

		// format that data and set GridBuilder.expands
		end_data.map(function(dataset){
			dataset = dataset.map(function(d){ d.parts = (d.id ? d.id.split('/') : [d.name]); return d; });

			GridBuilder.setExpandValue(dataset);
		});
	},

	updateFilters:function(grid){
		var grid = $('[name=tbfilters] [name=grid]');
		var data = grid.data('kendoGrid').dataSource.data().toJSON();

		data.map(function(d){
			// if our value type is number then convert
			if(
				d.type.toLowerCase().indexOf('int') > -1 ||
				d.type.toLowerCase().indexOf('decimal') > -1 
			  ){
				d.value = parseFloat(d.value);
			}
		})

		GridBuilder.filters = data;
	},

	setExpandValue:function(data){
		// function to find the base level object
		function findBase(parts, parent){
			if(parts.length === 0){
				return parent;
			}
			else{
				var next = parent.expands.filter(function(x){ return x.field == parts[0] })[0];
				if(next){
					parts.shift();
					return findBase(parts, next);
				}
			}
		}

		// we know a given dataset will all have the same parent;
		if(data.length > 0){
			var parts = data[0].parts;
			parts.pop();
			var parent = null;
			var formattedData = data.filter(GridBuilder.notScalar).map(function(d){ return { field: d.name, selects:[], expands:[] }});

			if(parts.length === 0){
				// we know there are no parents so we can set the base.
				GridBuilder.expands = formattedData;
			}
			else{
				// we need to find the parent;
				parent = parent || (GridBuilder.expands || []).filter(function(x){ return x.field === parts[0] })[0]; // if there isn't one for the top parts option then we dont want tog o further
				if(parent){
					// remove top part
					parts.shift();
					// find the base level object
					var key = findBase(parts, parent);
					// set value
					key.selects = data.filter(GridBuilder.isScalar).map(GridBuilder.formatChildProperty);
					key.expands = formattedData;
				}
			}
		}
	},

	onBind:function(e){
		var grid = e.sender.element;		

		$('[name=add]', grid).off('click').on('click',{grid, grid}, GridBuilder.addCol);

		var rows = $('tr', grid);

		// make sure any columns that are for scalar properties do not give detail init functionality
		for(var r = 0; r < rows.length; r++){
			var row = rows[r];
			var dataitem = grid.data('kendoGrid').dataItem(row);

			if(dataitem && dataitem.isScalar){
				$('.k-icon', row).remove();
			}
		}

		// handle checkbox click
		$('[type=checkbox]', grid).off('click').on('click', {grid: grid}, GridBuilder.handleCheck);
		$('[type=checkbox].chkGrouped', grid).off('click').on('click', {grid: grid}, GridBuilder.handleGroupCheck);
		$('[type=checkbox].chkSort', grid).off('click').on('click', {grid: grid}, GridBuilder.handleSortCheck);
		$('[type=checkbox].chkHidden', grid).off('click').on('click', {grid: grid}, GridBuilder.handleHiddenCheck);

		$('[type=radio]', grid).off('click').on('click', {grid: grid}, GridBuilder.handleRadio);

		$('[name=checkall]', grid).off('click').on('click', function(e){
			var checked = this.checked;
			var datagrid = grid.data('kendoGrid');

			datagrid.dataSource.data(
				datagrid.dataSource.data().map(function(d){ d.selected = checked; return d ;})
			)
		});

		GridBuilder.updateSelects(grid);
		GridBuilder.updateExpands(grid);
	},

	addCol:function(e){
		e.data.grid.data('kendoGrid').dataSource.add({
			name:'',
			title:'',
			template:'',
			templateType:'',
			isScalar:false,
			selected:true,
			group: false,
			order:0,
			width:'auto',
			sort: false,
			hidden: false
		});
	}
}

