LayoutMigration = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=LayoutMigration]");
        api.addToMetaCache([
            {
                "Name": "Core",
                "Types": [
                    [meta[Core/App]]
                ]
            }
        ]);

        var list = (await api.get("Core/Layout?$filter=AppId eq " + app.Id + "&$select=Name")).value;
        var g = new GridWidget($("[name=layoutGrid]", container), list);
        g.columns = [
            { selectable: true, width: 40 },
            {
                field: "Name",
            }
        ];
        g.groupable = false;
        g.init(() => {
            g.kendoObject.dataSource.sort({ field: "Name", dir: "asc" });
            g.kendoObject.select(g.kendoObject.tbody.find(">tr"));
        });
        $("[name=migrate]", container).on("click", async function (e) {
            var packages = await LayoutMigration.getPackages($("[name=layoutGrid]", container), app);
            var appId = $("[name=app]", container).val();
            await api.add("Packaging/Package/ImportThis?appId=" + appId, packages);
            notification.success("[resource_displayname[migrated]]");
        });
    },

    initDropdown: async function(container) {
        let ds = await model.getDatasource({
            endpoint: "Core/App"
        });

        $("[name=app]", container).kendoDropDownList({
            optionLabel: "[resource_displayname[selectapp]]",
            dataTextField: "Name",
            dataValueField: "Id",
            dataSource: ds
        });
    },

    getPackages: async function (container, app) {
        var packages = [{
            Id: "00000000-0000-0000-0000-000000000000",
            Name: "Layouts",
            Description: "Generated by LayoutManagement",
            Category: "Dynamic",
            SourceApi: session.apiRoot,
            Items: [
                await LayoutMigration.getPackage(container, app)
            ]
        }];
        return packages;
    },

    getPackage: async function (container, app) {
        var grid = $(container).find(".k-grid").data("kendoGrid");
        var layouts = [];
        grid.select().each(function () {
            layouts.push(grid.dataItem(this).Name);
        });
        var query = "";
        for (var i = 0; i < layouts.length; i = i + 1) {
            query += "'" + layouts[i] + "',";
        }
        query = query.substring(0, query.length - 1);
        var data = await api.get("Core/Layout?$filter=AppId eq " + app.Id + " and Name in (" + query + ")");
        for (var i = 0; i < data.value.length; i = i + 1) {
            delete data.value[i].Id;
        }
        return {
            Id: "00000000-0000-0000-0000-000000000000",
            PackageId: "00000000-0000-0000-0000-000000000000",
            Type: "Core/Layout",
            Data: JSON.stringify(data.value)
        };
    }
};

Login = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $("[name=Login]");

		var confirmation = {
			SSOUserId: getQueryParameter("u"),
			Token: getQueryParameter("t")
		};

		if (confirmation.SSOUserId && confirmation.Token) {
			var r = await api.post("Account/ConfirmEmail", confirmation);
			if (r === true)
				notification.success("[resource_description[TokenVerificationSuccess]]");
			else
				notification.warning("[resource_description[TokenVerificationFailed]]");
		}

		if (window.location.href.indexOf("AccessDenied") != -1) {
			notification.error("Access Denied!");
		}

		var login = async function (e) {
			notification.info("[resource_displayname[loggingin]]");
			var result = await api.login(
				$("[name=user]").val(),
				$("[name=pass]").val(),
				true
			);

			if (result.id) {
				session.token = api.token;
				await Login.success(e);
			}
		};

		$("button[name=login]", container).on("click", login);
		$("[name=pass]").on("keyup", async function (e) {
			if (event.keyCode === 13)
				await login(e);
		});

		$("[name=forgotPass]", container)
			.off()
			.on("click", Login.forgotPassword);

		$("[name=register]", container).on("click", function (e) {
			Login.register(e, app);
		});

		$("[name=pass] .k-icon.k-i-preview").on("click", function () {
			$("[name=pass] > .value > input")
				.attr("type", ($("[name=pass] > .value > input")
				.attr("type") == "password" ? "text" : "password"));
		});
	},

	register: function(e, app) {
		e.preventDefault();
		var d = new Dialog({
			title: "[resource_displayname[register]]",
			width: 620,
			height: 550
		});
		d.template = $("[name=registerComponent]").first().html();
		d.init(() => Register.init(app, $(".component[name=Register]", d.element), d));
	},

	forgotPassword: function (e) {
		e.preventDefault();
		var d = new Dialog({
			title: "[resource_description[PasswordResetEmailTitle]]"
		});
		d.template = $("script[name=ForgotPass]").html();
		d.events.submit = async function (e) {
			if($("[name=forgotPasswordForm]", d.element).getKendoValidator().validate()) {
				var request = {
					Email: $("input[name=email]", d.element).val(),
					AppId: session.app.Id,
					Culture: session.culture
				};
				var e = await api.post("Account/ForgotPassword", request);
				notification.success("[resource_description[CheckYourEmail]]");
				d.events.close();
			}
		};
		d.init(() => {
			$("[name=forgotPasswordForm]", d.element).kendoValidator();
		});
	},

	success: async function (e) {
		var user = await api.get("Core/User/Me()");
		var newLocation = getQueryParameter("returnUrl") || window.location.href.replace("Login", "");
		newLocation = setUrlQueryParameter(newLocation, "t", api.token);
		if(window.location.toString().indexOf("culture=") === -1) {
			if (newLocation.indexOf("?") !== -1) {
				window.location.href = newLocation + "&culture=" + user.DefaultCultureId;
			} else {
				window.location.href = newLocation + "?culture=" + user.DefaultCultureId;
			}
		} else {
			window.location.href = newLocation;
		}
	},

	failed: function (e) {
		notification.error("[resource_description[AccessDenied]]");
	}
};

Metadata = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=Metadata]");
        var swaggerDefinition = await api.get("../swagger/v1/swagger.json");
        var dataSource = await Metadata.getDatasource();
        var grid = new GridWidget(container, { data: dataSource, pageSize: 1000, group: { field: "Category", dir: "asc"} });
        grid.editable = false;
        grid.columns = [
            { field: "Category", title: "[resource_displayname[context]]", width: 200 },
            { field: "DisplayName", title: "[resource_displayname[displayname]]", width: 200 },
            { field: "url", title: "[resource_displayname[url]]", template: "#:session.apiRoot##:Category#/#:DisplayName#" }
        ];

        grid.detailTemplate = $("script[name=metadataDetails]", container).first().html();
        grid.detailExpand = async function(e) {
            var container = $(e.detailRow);
            var meta = this.dataItem(e.masterRow);
            if($(".k-tabstrip", container).length == 0) {
                $("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });
                var editor = new MonacoEditor($("[name=rawJson]", container)[0], {
                    code: JSON.stringify(meta, null, '\t'),
                    language: "json",
                    automaticLayout: true
                });
                editor.init();
                await Metadata.setupMetaPropertiesGrid(container, meta);
                await Metadata.setupEndpoints(container, meta, swaggerDefinition.paths, app);
                await Metadata.setupDependencies(container, meta);
            }
        };
        await grid.init();

    },

    getDatasource: async function() {
        var data = [];
        var allMeta = await api.get("Getmetadata");

        var contexts = allMeta.filter(i => i.UriBase);
        contexts.forEach((context) => {
            var entities = context.Types.filter(t => t.IsEntity && t.HasEndpoint).sort((t1, t2) => t1.DisplayName > t2.DisplayName ? 1 : -1);
            entities.forEach((item) => {
                item.id = item.Category + '/' + item.DisplayName;
                item.testStatus = "loading";
                item.isUp = "loading";
                data.push(item);
            })
        });

        window.allMeta = data;;

        return data;
    },

    setupMetaPropertiesGrid: async function (container, meta) {
        var propertyGrid = new GridWidget($("[name=properties]", container), { data: meta.Properties, pageSize: 50 });
        propertyGrid.exports = false;
        propertyGrid.editable = false;
        propertyGrid.groupable = false;

        propertyGrid.columns = [
            { field: "Name", title: "[resource_displayname[name]]" },
            { field: "Type", title: "[resource_displayname[type]]" },
            { field: "ServerType", title: "[resource_displayname[servertype]]" },
            { field: "ServerTypeName", title: "[resource_displayname[servertypename]]" },
            { field: "Template", title: "[resource_displayname[template]]" },
            { field: "DisplayName", title: "[resource_displayname[displayname]]" },
            { field: "ShortDisplayName", title: "[resource_displayname[shortdisplayname]]" },
            { field: "Description", title: "[resource_displayname[description]]" },
            { field: "IsGeneric", title: "[resource_displayname[isgeneric]]", type: "boolean" },
            { field: "IsValueType", title: "[resource_displayname[isvaluetype]]", type: "boolean" },
            { field: "IsReadOnly", title: "[resource_displayname[isreadonly]]", type:"boolean" },
            { field: "IsRequired", title: "[resource_displayname[isrequired]]", type: "boolean" }
        ];
        await propertyGrid.init();
    },

    setupEndpoints: async function(container, meta, swaggerPaths, app) {
        var applicableEndpointKeys = Object.keys(swaggerPaths).filter(r => r.indexOf("/Api/" + meta.id) !== -1);
        var applicableEndpoints = applicableEndpointKeys.map(endpointURL => 
            Metadata.getHttpMethods(swaggerPaths[endpointURL]).map(httpMethodName => ({
                "endpoint": endpointURL,
                "data": swaggerPaths[endpointURL][httpMethodName.toLowerCase()],
                "method": httpMethodName
            }))).flat();

        var endpointGrid = new GridWidget($("[name=endpoints]", container), { data: applicableEndpoints, pageSize: 20 });
        endpointGrid.groupable = false;
        endpointGrid.columns = [
            { field: "method", title: "[resource_displayname[methods]]", template: "#=method#", width: 80 },
            { field: "endpoint", title: "[resource_displayname[endpoint]]", template: "#=endpoint#" },
        ];
        endpointGrid.dataBound = function() {
            $("[name=explore]", endpointGrid.gridElement).on("click", (e) => Metadata.explore(e, app, endpointGrid));
        };

        endpointGrid.commands.push({name: "explore", icon: "k-i-search", text: "[resource_displayname[explore]]" });

        await endpointGrid.init();
    },

    setupDependencies: async function(container, meta) {
        var foreignKeys = meta.Properties.filter(p => p.Name.endsWith("Id") && p.Name != "Id" &&  
            meta.Properties.filter(p2 => p2.Name == p.Name.substring(0, p.Name.length - 2) && p2.Type == "object").length > 0);

        foreignKeys.map(fk => {
            var object = meta.Properties.filter(p2 => p2.Name == fk.Name.substring(0, fk.Name.length - 2) && p2.Type == "object")[0];
            var serverTypeInformation = object.ServerType;
            var entity = window.allMeta.filter(metaEntry => metaEntry.ServerType.startsWith(serverTypeInformation))[0];
            fk.RelatedEntity = entity;
        });

        var dependsOnGrid = new GridWidget($("[name=dependson]", container), { data: foreignKeys, pageSize: 50 });
        dependsOnGrid.exports = false;
        dependsOnGrid.editable = false;
        dependsOnGrid.columns = [
            { field: "Name", title: "[resource_displayname[foreignkey]]" },
            { field: "Type", title: "[resource_displayname[type]]"},
            { field: "IsRequired", type:"boolean", title: "[resource_displayname[isrequired]]"},
            { field: "ServerType", title: "[resource_displayname[servertype]]"},
            { field: "RelatedEntity.id", title: "[resource_displayname[relatedentity]]"}
        ];
        dependsOnGrid.init();
    },

    explore: async function(e, app, endpointGrid) {
        e.preventDefault();
        var item = endpointGrid.dataItem($(e.currentTarget).closest("tr"));

        var exploreDialog = new Dialog({title: "[resource_displayname[explore]]", width: 1900, height: 805 });
        exploreDialog.init(async () => {
            var apiTesterComponent = await loadComponent(exploreDialog.element, "ApiTester");
            var endpointPath = item.endpoint.substring(item.endpoint.indexOf("/Api/")+5);
            if(item.data.parameters && item.data.parameters.filter(r => r.name == "queryOptions" && r.schema["$ref"].indexOf("ODataQueryOptions") !== -1).length > 0) {
                endpointPath += "?$top=10";
            }

            apiTesterComponent.init(app, $(".component[name=ApiTester]", exploreDialog.element), item.method, endpointPath);
        });
    },

    getHttpMethods: function(swaggerPathEntry) {
        return Object.keys(swaggerPathEntry).map(o => o.toUpperCase());
    }
};

