QueryBuilder = {
	defaultGridHeight: 300,
	init: function (app, container, dmsPath) {
        if(!app) { app = session.app; }
        if (!container) { container = $(".component[name=QueryBuilder]"); }
        if(!dmsPath) { dmsPath = "Data/QueryBuilder/" + session.user.Id; }

		// pass api root to the api root label on the page
		$("span[name=apiRoot]").text(session.apiRoot);

		// fetch a list of contexts
		api.get('', function (data) {
            $('[name=contextList]', container).kendoDropDownList({
                dataTextField: "name",
                dataValueField: "url",
                dataSource: data.value,
                index: 0,
                change: function (e) { QueryBuilder.onContextChange(container); }
			});

			// raise selection changed handler to build next portion
			QueryBuilder.onContextChange(container);
		});

        $('button[name=build]', container).on('click', function(e) { QueryBuilder.build(app, container, dmsPath); });
    },

    build: function(app, container, dmsPath) {
            $(document.body).append($("<div name='componentBuilder'>" + $("[name=generatedComponent]", container).html() + "</div>"));
            var dialog = $("[name=componentBuilder]").kendoWindow({
				title: "[resource_displayname[ComponentDetails]]",
				modal: true,
                visible: false,
                width: "80%",
				close: function(){ this.destroy(); $("body > [name=componentBuilder]").remove(); }
            });

            var config = QueryBuilder.buildGridConfiguration(container);
            var markup = "<div name='query'></div>";
            var code = 
                  "NewComponent = {\n" +
                  "    init: function(app, container) {\n" +
                  "          if(!app) { app = session.app; }\n" +
                  "          if(!container) { container = $('.component[name=NewComponent]'); }\n" +
                  "          model.prepConfigForGrid($('div[name=query]', container), NewComponent.getConfig(), function(c) {\n" + 
                  "                  $('[name=grid]', container).kendoGrid(c);\n" + 
                  "           });\n" +
                  "     },\n" +
                  "     getConfig: function() {\n" +
                  "          return JSON.parse(" + JSON.stringify(config, null, '    ') + ");\n" +
                  "      }\n" +
                  "}\n" + 
                  "$(function() { NewComponent.init(); });";

           $("pre[name=html]", dialog).text(markup);
		   $("pre[name=script]", dialog).text(code);
		   dialog.data("kendoWindow").center().open();

       	   $("button[name=create]", dialog).on("click", function(e) {
                 model.item.createInstance("ContentManagement/Component", function(component) {
                    component.AppId = app.Id;
                    component.Name = $("input[name=name]", dialog).val();
                    component.Description = $("input[name=description]", dialog).val();
                    component.Category = $("input[name=category]", dialog).val();
					component.Html =  $("pre[name=html]", dialog).text();
                    component.Script = $("pre[name=script]", dialog).text();
                    component.save(function(res) {
                       notification.success("[resource_description[ComponentCreated]]");
                    });
                 });
           });

       	   $("button[name=saveConfig]", dialog).on("click", function(e) {
                 api.add("DMS/" + path, function(res) {
                      notification.success("[resource_description[ConfigurationSaved]]");
              	 });
           });
    },

	onContextChange: function (container) {
		api.get($('[name=contextList]', container).val(), function (data) {
            var endpointList = $('[name=endpointList]', container);

			// remove the old if there is one
			var oldCtrl = endpointList.data("kendoDropDownList");
			if (oldCtrl) {
				oldCtrl.destroy();
				endpointList.empty();
			}

			// buld the new
            endpointList.kendoDropDownList({
                dataTextField: "name",
                dataValueField: "url",
                dataSource: data.value,
                index: 0,
                change: function (e) { QueryBuilder.onEndpointChange(container); }
			});

			// raise selection changed handler to build next portion
			QueryBuilder.onEndpointChange(container);
		});
	},

	// for when endpoint selection is changed
	onEndpointChange: function (container) {
		var ctxList = $('[name=contextList]', container);
		var endpointList = $('[name=endpointList]', container);

		log('endpoint selected ' + ctxList.val() + "/" + endpointList.val(), 'debug');
		type.get(ctxList.val() + '/' + endpointList.val(), function (meta) {
			log(meta, 'debug');
			QueryBuilder.buildSelectGrid(meta, container);
			QueryBuilder.buildExpandGrid(meta, container);
			QueryBuilder.buildFilterGrid(container);
			QueryBuilder.generate(container);
		});
	},

	// builds the column / selection grid
	buildSelectGrid: function (meta, container) {
		var colList = $('[name=columnList]', container);
		var count = 0;
		var data = JSLINQ(meta.Properties)
			.Select(function (i) {
				i.id = i.Name;
				i.Selected = type.ofProperty.isScalar(i);
				i.DisplayOrder = count++;
				i.Width = 0;
				i.TemplateSource = QueryBuilder.buildDefaultTemplateSourceFor(i);

				return i;
			})
			.ToArray();

		var oldCtrl = colList.data("kendoGrid");
		if (oldCtrl) {
			oldCtrl.destroy();
			colList.empty();
		}

		var config = {
			scrollable: true,
			sortable: false,
			filterable: false,
			pageable: false,
			editable: true,
            height: 300,
			toolbar: ["create"],
			columns: [
				{ title: "", width: 70, template: "<input name='Selected' type='checkbox' data-bind='checked: Selected' #= data.Selected ? checked='checked' : '' #/>" },
				{ field: 'DisplayOrder', title: '[resource_shortdisplayname[DisplayOrder]]', width: 60 },
				{ field: 'DisplayName', title: '[resource_shortdisplayname[DisplayName]]', width: 200 },
				{ field: 'Width', title: '[resource_shortdisplayname[Width]]', width: 100 },
				{ field: 'TemplateSource', title: '[resource_shortdisplayname[TemplateSource]]' }
            ],
            dataSource: JSLINQ(data).Where(function (c) { return type.ofProperty.isScalar(c); }).ToArray()
		};
		colList.kendoGrid(config);
        $("input", colList).on('change', function (e) { QueryBuilder.generate(cotnainer); });
		$("input[name=Selected]", colList).off('change');

		colList.on("change", "input[name=Selected]", function (e) {
			var g = colList.data("kendoGrid");
			var row = $(e.target).closest("tr");
			var item = g.dataItem(row);
			item.Selected = $(e.target).is(":checked") ? true : false;
			QueryBuilder.generate(container);
		});
	},

	// builds the fetch / expansion grid
	buildExpandGrid: function (meta, container) {
        var expandList = $('[name=expandList]', container);
		var data = JSLINQ(meta.Properties)
			.Select(function (i) {
				i.id = i.Name;
				i.parentId = null;
				i.isScalar = type.ofProperty.isScalar(i);
				i.Selected = false;
				i.TemplateSource = QueryBuilder.buildDefaultTemplateSourceFor(i);
				return i;
			})
			.Where(function (i) { return !i.isScalar; })
			.ToArray();

		// ifthere's a previous grid, rip it out
		var oldGrid = expandList.data("kendoTreeList");
		if (oldGrid) {
			oldGrid.destroy();
			expandList.empty();
		}
		// build config for the new grid
		var config = {
			scrollable: true,
			sortable: false,
			filterable: false,
			pageable: false,
			editable: true,
            height: 300,
			columns: [
				{ title: '', width: 100, template: "<span class='k-icon #:isScalar ? '' : 'k-i-expand' # not-loaded'>&nbsp;</span>" },
				{ title: "", width: 70, template: "<input name='Selected' type='checkbox' data-bind='checked: Selected' #= data.Selected ? checked='checked' : '' #/>" },
				{ field: 'Name', title: '[resource_shortdisplayname[Name]]' },
				{ field: 'Type', title: '[resource_shortdisplayname[Type]]' }
            ],
			dataSource: new kendo.data.TreeListDataSource({
				data: data,
				schema: { model: { id: "id", expanded: true } }
			})
		};

		// tell kendo to build it
		expandList.kendoTreeList(config);

		// hook up input element value changes to handle re-building the result automatically when user "changes stuff"
		$("input", expandList).on('change', function(e) { QueryBuilder.generate(container); });
		$("input[name=Selected]", expandList).off('change');

		expandList.on("change", "input[name=Selected]", function (e) {
			var g = expandList.data("kendoTreeList");
			var row = $(e.target).closest("tr");
			var item = g.dataItem(row);
			item.Selected = $(e.target).is(":checked") ? true : false;
			QueryBuilder.generate(container);
		});

		expandList.off('click', '.k-i-expand.not-loaded');
		expandList.on('click', '.k-i-expand.not-loaded', function (e) {
			var source = expandList.data("kendoTreeList");
			var selectedItem = source.dataItem($(e.currentTarget).closest('tr'));
            var typeDefParts = selectedItem.ServerType.split(',')[0].split('.');
            var endpoint = $('[name=contextList]', container).val() + '/' + typeDefParts[typeDefParts.length-1];
			type.get(endpoint, function (meta) {
				var newData = JSLINQ(meta.Properties)
					.Select(function (i) {
						i.id = selectedItem.id + "/" + i.Name;
						i.parentId = selectedItem.id;
						i.isScalar = type.ofProperty.isScalar(i);
						i.Selected = false;
						i.TemplateSource = QueryBuilder.buildDefaultTemplateSourceFor(i);
						return i;
					})
					.ToArray();

				for (var i in newData) { source.dataSource.add(newData[i]); }

				$(e.currentTarget).remove();
				source.expand(selectedItem);
				QueryBuilder.buildFilterGrid(container);
				QueryBuilder.generate(container);
			});
		});
	},

	buildFilterGrid: function (container) {
        var colList = $('[name=columnList]', container);
        var expandList = $('[name=expandList]', container);
        var filterList = $('[name=filterList]', container);
		var colOptions = JSLINQ(expandList.data("kendoTreeList").dataSource.data().toJSON())
			.Where(function (c) { return c.Selected && type.ofProperty.isScalar(c); })
			.Concat(JSLINQ(colList.data("kendoGrid").dataSource.data().toJSON()).ToArray())
			.ToArray();

		// http://docs.oasis-open.org/odata/odata/v4.0/errata03/os/complete/part2-url-conventions/odata-v4.0-errata03-os-part2-url-conventions-complete.html#_Toc453752358
		var conditionOptions = [
			{ id: 'eq',	text: 'is equal to' },
			{ id: 'neq',text: 'is not equal to' },
			{ id: 'gt', text: 'is greater than' },
			{ id: 'lt', text: 'is less than' },
			{ id: 'le', text: 'is less than or equal to' },
			{ id: 'ge', text: 'is greater than or equal to' }
        ];

		// if there's a previous grid, rip it out
		var oldGrid = filterList.data("kendoGrid");
		if (oldGrid) {
			oldGrid.destroy();
			filterList.empty();
		}

		var fieldEditor = function (container, options) {
			$("<input name='field' />")
				.appendTo(container)
				.kendoDropDownList({
					dataTextField: "id",
					dataValueField: "id",
					dataSource: colOptions,
					index: 0,
					select: function (e) {
						var grid = $(filterList).data("kendoGrid");
						var row = $(e.sender.element).closest('tr');
						var filter = grid.dataItem(row);
						filter.meta = this.dataItem(e.item ? e.item.index() : e.sender.selectedIndex);
						filter.field = filter.meta.id;
					}
				});

			$("[name=field]", container).data("kendoDropDownList").trigger("select");
		};

		var conditionEditor = function (container, options) {
			$("<input name='condition' />")
				.appendTo(container)
				.kendoDropDownList({
					dataTextField: "text",
					dataValueField: "id",
					dataSource: conditionOptions,
					index: 0,
					select: function (e) {
						var grid = $(filterList).data("kendoGrid");
						var row = $(e.sender.element).closest('tr');
						var filter = grid.dataItem(row);
						filter.operator = this.dataItem(e.item ? e.item.index() : e.sender.selectedIndex).id;
					}
				});

			$("[name=condition]", container).data("kendoDropDownList").trigger("select");
		};

		// build config for the new grid
		var config = {
			scrollable: true,
			sortable: false,
			filterable: false,
			pageable: false,
			editable: 'inline',
			toolbar: ["create"],
			columns: [
				{ field: 'field', title: '[resource_shortdisplayname[Field]]', editor: fieldEditor },
				{ field: 'operator', title: '[resource_shortdisplayname[Operator]]', editor: conditionEditor },
				{ field: 'Value', title: '[resource_shortdisplayname[Value]]' },
				{ command: ['destroy'] }
            ],
			dataSource: new kendo.data.DataSource({ data: new Array() }),
            dataBound: function (e) { $(e.sender.element).css('max-height' + QueryBuilder.defaultGridHeight + 'px'); }
		};

		// tell kendo to build it
		filterList.kendoGrid(config);

		// hook up input element value changes to handle re-building the result automatically when user "changes stuff"
        $(filterList).on('change', "input", function () { QueryBuilder.generate(container); });
	},

	buildDefaultTemplateSourceFor: function (col) {
        if (col.Type === 'date') { return "#: kendo.toString(new Date(" + col.Name + "), 'dd/MM/yyyy') #"; }
        else { return "#: " + col.Name + " #"; }
	},

    generate: function (container) {
        var grid = $('[name=grid]', container);
        var oldGrid = grid.data("kendoGrid");
        if (oldGrid) {
            oldGrid.destroy();
            grid.empty();
        }
        model.prepConfigForGrid( QueryBuilder.buildGridConfiguration(container), function (config) { grid.kendoGrid(config); });			
    },

	buildGridConfiguration: function (container) {
        var ctxList = $('[name=contextList]', container);
        var endpointList = $('[name=endpointList]', container);
        var colList = $('[name=columnList]', container);
        var expandList = $('[name=expandList]', container);
        var filterList = $('[name=filterList]', container);

		var cols = JSLINQ(colList.data("kendoGrid").dataSource.data().toJSON())
			.Where(function (c) { return c.Selected; })
            .ToArray()
            .sort((a, b) => a.DisplayOrder - b.DisplayOrder);

		var expands = JSLINQ(expandList.data("kendoTreeList").dataSource.data().toJSON())
			.Where(function (c) { return c.Selected; })
			.ToArray();

		var query = QueryBuilder.buildQuery(cols, expands, container);
		$("span[name=query]").text(query);

		return {
			scrollable: true,
			sortable: true,
			filterable: true,
			pageable: { refresh: true, pageSizes: true, buttonCount: 5 },
			columns: QueryBuilder.buildColumns(cols, expands),
			sourceInitParams: {
				endpoint: ctxList.val() + "/" + endpointList.val(),
				odataAppend: query,
				filter: {
					logic: 'and',
					//not sure how to handle complex object or collection filters yet
					//TODO: figure out complex filtering scenarios and how to handle them
					filters: JSLINQ(filterList.data("kendoGrid").dataSource.data())
						.Where(function (f) { return type.ofProperty.isScalar(f.meta); })
						.ToArray()
				}
			}
		};
	},

	buildColumns: function (selectedCols) {
		return JSLINQ(selectedCols).Select(function (col) {
			var template = col.TemplateSource ? col.TemplateSource : $("#" + col.Template).html();
			return { field: col.Name, title: "[resource_shortdisplayname[" + col.Name + "]]", template: kendo.template(template) };
		}).ToArray();
	},

	buildQuery: function (selectedCols, expands, container) {
		var colList = $('[name=columnList]', container);
		var result = '';

		// build selection array
		var selects = JSLINQ(selectedCols)
			.Where(function (c) { return type.ofProperty.isScalar(c); })
			.Select(function (c) { return c.Name; })
			.ToArray();

		// clear it if everything is selected (we don't need a sub select in this case)
		if (JSLINQ(colList.data("kendoGrid").dataSource.data().toJSON()).All(function (c) { return c.Selected; })) {
			selects = new Array();
		}

		var select = function (c) {
			var subSelections = JSLINQ(expands)
				.Where(function (c2) { return type.ofProperty.isScalar(c2) && c2.parentId === c.id; })
				.Select(select)
				.ToArray();

			var subIncludes = JSLINQ(expands)
				.Where(function (c2) { return !type.ofProperty.isScalar(c2) && c2.parentId === c.id; })
				.Select(select)
				.ToArray();

			if (subSelections.length === 0 && subIncludes.length === 0) {
				return c.Name;
			} else {
				var result = c.Name + '(';
				if (subSelections.length > 0) { result += '$select=' + subSelections.join(); }
                if (subIncludes.length > 0)   { result += ';$expand=' + subIncludes.join() + ')'; }
				return result + ')';
			}
		};

		// build an expands array
		expands = JSLINQ(expands)
			.Where(function (c) { return !type.ofProperty.isScalar(c) && !c.id.includes('/'); })
			.Select(select)
			.ToArray();

		// if we have selections, build out the select part ofthe query
		if (selects.length > 0) { result += "?$select=" + selects.join(); }

		// if we have any expands, build out the expand part of the query
		if (expands.length > 0) {
			if (selects.length > 0) { result += "&$expand=" + expands.join(); }
            else { result += "?$expand=" + expands.join(); }
		}

		// return the resulting query
		return result;
	}
};

Register = {
	init: function (app, container,dialog, callback = null) {
		app = app || session.app;
		container = container || $(".component[name=Register]");
		var model = new kendo.data.ObservableObject({
			DisplayName: null,
			Email: null,
			Password: null,
			ConfirmPassword: null,
			AppId: session.app.Id,
			Culture: session.culture,
			PhoneNumber: null,
			DPP: false,
			TAC: false
		});

		kendo.bind(container, model);
		container.data("model", model);
		container.kendoValidator({
			rules: {
				passwordsMatch: function(input) {
					var ret = true;
					if(input.is("[name=ConfirmPassword]")) {
						ret = input.val() === $("input[name=Password]", container).val()
					}
					return ret;
				}
			},
			messages: {
				passwordsMatch: "[resource_description[passwordsDontMatch]]"
			}
		});

		$("button[name=register]", container).on("click", function (e) {
			Register.submit(e, container, dialog, callback, app);
		});
	},

	submit: function (e, container, d, callback, app) {
		e.preventDefault();
		var model = {
			DisplayName: $("input[name=DisplayName]", container).val(),
			Email: $("input[name=Email]", container).val(),
			Password: $("input[name=Password]", container).val(),
			ConfirmPassword: $("input[name=ConfirmPassword]", container).val(),
			TAC: $("input[name=TAC]").is(":checked"),
			DPP: $("input[name=DPP]").is(":checked"),
			AppId: app.Id
		};

		$("button[name=submit]", container).attr('disabled', true);       
		if (container.getKendoValidator().validate() && model.DPP && model.TAC) {
			notification.info("Submitting, Please Wait ...");
			api.register(model).then((registerResult) => {
				d.events.close();
				Register.success(registerResult, container, model, callback)
			}).catch((e) => Register.failed(e, container));
		} 
		else {
			if(!model.TAC) {
               var field = $("input[name=TAC]", container);
               field.addClass("is-invalid");
               field.attr("aria-invalid", "true");
			}
			if(!model.DPP) {
               var field = $("input[name=DPP]", container);
               field.addClass("is-invalid");
               field.attr("aria-invalid", "true");
			}

			notification.error("[resource_description[PleaseResolveValidationIssues]]");
		}
	},

	success:async  function (registerResult, container, loginModel, callback) {
		if ('id' in registerResult) {
			notification.info("[resource_description[ConfirmationEmailSentTo]]".replace("EMAIL", $("input[name=Email]", container).val()));
			await api.login(loginModel.Email, loginModel.Password).then(() => {
				if(Login) {
					Login.success();
				}
				callback();
			});
		} else { 
			Register.failed(registerResult, container); 
		}
	},

	failed: function(registerResult, container) {
		$("button[name=submit]", container).attr('disabled', false);
         for(var i in registerResult.responseJSON) {
         	   var field = $("input[name=" + i + "]");
               var fieldContainer = field.parent();
               field.addClass("k-invalid");
               field.attr("aria-invalid", "true");
               for(var j in registerResult.responseJSON[i]) {
                   fieldContainer.append(
                      "<span class='k-widget k-tooltip k-tooltip-validation k-invalid-msg' data-for='" + i + "' role='alert'>" +
                                "<span class='k-icon k-i-warning'></span>" + registerResult.responseJSON[i][j] + 
                      "</span>");
               }
         }
		 error(registerResult);
	}
}

