ResourceMigration = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=ResourceMigration]");
        api.addToMetaCache([
        {
            "Name": "Core",
            "Types": [
                [meta[Core/App]]
            ]
        }]);

        var resourceKeys = await api.get("Core/Resource?$filter=AppId eq " + app.Id + "&$select=Key");
        var list = [...new Set(resourceKeys.value.map(item => item.Key))].map(x => ({ Key: x }))
        var g = new GridWidget($("[name=resourceGrid]", container), list);
        g.columns = [
            { selectable: true, width: 40 },
            {
                field: "Key",
            }
        ];
        g.groupable = false;
        g.init(() => {
            g.kendoObject.dataSource.sort({ field: "Key", dir: "asc" });
            g.kendoObject.select(g.kendoObject.tbody.find(">tr"));
        });
        $("[name=migrate]", container).on("click", async function (e) {
            notification.info("[resource_displayname[migrating]]");
            var packages = await ResourceMigration.getPackages($("[name=resourceGrid]", container), app);
            var appId = $("[name=app]", container).val();
            await api.add("Packaging/Package/ImportThis()?appId=" + appId, packages);
            notification.success("[resource_displayname[migrated]]");
        });
    },

    initDropdown: async function(container) {
        let ds = await model.getDatasource({
            endpoint: "Core/App"
        });
        $("[name=app]", container).kendoDropDownList({
            autoBind: false,
            optionLabel: "[resource_displayname[selectapp]]",
            dataTextField: "Name",
            dataValueField: "Id",
            dataSource: ds
        });
    },

    getPackages: async function (container, app) {
        var packages = [{
            Id: "00000000-0000-0000-0000-000000000000",
            Name: "Resources",
            Description: "Generated by ResourceMigration",
            Category: "Dynamic",
            SourceApi: session.apiRoot,
            Items: [
                await ResourceMigration.getPackage(container, app)
            ]
        }];
        return packages;
    },

    getPackage: async function (container, app) {
        var grid = $(container).find(".k-grid").data("kendoGrid");
        var keys = [];
        grid.select().each(function () {
            keys.push(grid.dataItem(this).Key);
        });
        var query = "";
        for (var i = 0; i < keys.length; i = i + 1) {
            query += "'" + keys[i] + "',";
        }
        query = query.substring(0, query.length - 1);
        var data = await api.get("Core/Resource?$filter=AppId eq " + app.Id + " and Key in (" + query + ")");
        for (var i = 0; i < data.value.length; i = i + 1) {
            delete data.value[i].Id;
        }
        return {
            Id: "00000000-0000-0000-0000-000000000000",
            PackageId: "00000000-0000-0000-0000-000000000000",
            Type: "Core/Resource",
            Data: JSON.stringify(data.value)
        };
    }
};

