Scheduling = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".container[name=Scheduling]");
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Scheduling/ScheduledTask]],
					[meta[Workflow/FlowDefinition]],
					[meta[Core/User]]
				]
			}
		]);
		var scheduledTasks = await model.getDatasource({
			endpoint: "Scheduling/ScheduledTask",
			odataAppend: "?$filter=AppId eq " + app.Id + "&$expand=Flow",
			sort: {
				field: "Name",
				dir: "asc"
			}
		});
		var flowDefinitions = await model.getDatasource({
			endpoint: "Workflow/FlowDefinition",
			odataAppend: "?$filter=AppId eq " + app.Id + "&$expand=Process"
		});
		var users = await model.getDatasource({
			endpoint: "Core/User",
			odataAppend: "?$filter=Roles/any(r: r/Role/AppId eq " + app.Id + ")",
			pageSize: 1000
		});
		flowDefinitions.group({
			field: "Process.Name"
		});

		await Scheduling.initGrid(app, container, scheduledTasks, flowDefinitions, users);

		await loadComponent($('[name=flowInstanceManagementComponent', container), 'FlowInstanceManagement');
	},

	secondInTicks: 10000000,

	ticksToFriendly: function(value) {
		if(value === 0) { return "[resource_displayname[notimeperiod]]" }
		var seconds = value / Scheduling.secondInTicks;
		var days = Math.floor((seconds % 31536000) / 86400); 
		var hours = Math.floor(((seconds % 31536000) % 86400) / 3600);
		var minutes = Math.floor((((seconds % 31536000) % 86400) % 3600) / 60);
		var seconds = (((seconds % 31536000) % 86400) % 3600) % 60;
		var string = "";
		if(days > 1) { string += days + " [resource_displayname[days]] "; }
		else if(days === 1) { string += days + " [resource_displayname[day]] "; }

		if(hours > 1) { string += hours + " [resource_displayname[hours]] "; }
		else if(hours === 1) { string += hours + " [resource_displayname[hour]] "; }

		if(minutes > 1) { string += minutes + " [resource_displayname[minutes]] "; }
		else if(minutes === 1) { string += minutes + " [resource_displayname[minute]] "; }

		if(seconds > 1) { string += seconds + " [resource_displayname[seconds]] " }
		else if(seconds === 1) { string += seconds + " [resource_displayname[second]] "; }
		return string;
	},

	initGrid: async function(app, container, scheduledTasks, flowDefinitions, users) {
		var grid = new GridWidget(container, scheduledTasks);
		grid.groupable = false;
		grid.toolbar = [
			{
				template: `<div class='btn-group btn-group-sm'>
					<button class='btn btn-primary' name='create'>
						<span class='k-icon k-i-plus'></span>[resource_displayname[new]]
					</button>
				</div>`
			}
		];
		grid.columns = [
			{ field: "Name", title: "[resource_shortdisplayname[Name]]" },
			{ field: "Description", title: "[resource_shortdisplayname[Description]]" },
			{ 
				field: "ScheduleInTicks", 
				title: "[resource_shortdisplayname[Schedule]]", 
				type: "number",
				template: "#=Scheduling.ticksToFriendly(ScheduleInTicks)#",
				editor: function(container, options) {
					$('<input required name="' + options.field + '"/>').appendTo(container).kendoSlider({ 
						min: 0, 
						max: 86400 * Scheduling.secondInTicks * 14, 
						smallStep: Scheduling.secondInTicks * 3600, 
						largeStep: Scheduling.secondInTicks * 3600 * 24,
						tooltip: {
							template: "'#=Scheduling.ticksToFriendly(value)#'"
						}
					});
				}
			},
			{
				field: "FlowId",
				title: "[resource_shortdisplayname[Flow]]",
				template: "#=Flow.Name#",
				editor: function (container, options) {
					$('<input required name="' + options.field + '"/>')
						.appendTo(container)
						.kendoDropDownList({ autoBind: false, dataTextField: "Name", dataValueField: "Id", dataSource: flowDefinitions });
				}
			},
			{ 
				field: "CreatedBy", 
				title: "[resource_shortdisplayname[createdby]]", 
				width: "[theme[columns.small]]" , 
				editable: () => false 
			},
			{ 
				field: "Created", 
				title: "[resource_shortdisplayname[created]]", 
				format: "{0:" + type.dateFormat + "}", 
				width: "[theme[columns.date]]" , 
				editable: () => false 
			},
			{ 
				field: "UpdatedBy", 
				title: "[resource_shortdisplayname[updatedby]]", 
				width: "[theme[columns.small]]" , 
				editable: () => false 
			},
			{ 
				field: "LastUpdated", 
				title: "[resource_shortdisplayname[lastupdated]]", 
				format: "{0:" + type.dateFormat + "}", 
				width: "[theme[columns.date]]" , 
				editable: () => false 
			},
			{ 
				field: "LastExecuted", 
				title: "[resource_shortdisplayname[lastexecuted]]", 
				type: "date", 
				format: "{0:" + type.dateFormat + " HH:mm}", 
				width: "[theme[columns.small]]", 
				editable: () => false 
			},
			{ 
				field: "NextExecution", 
				title: "[resource_shortdisplayname[nextexecution]]", 
				type: "date", 
				format: "{0:" + type.dateFormat + " HH:mm}", 
				width: "[theme[columns.small]]",
				editor: function(container, options) {
                    $('<input required name="' + options.field + '"/>')
						.appendTo(container)
						.kendoDateTimePicker({
							autoBind: false,
							value: new Date(),
							dateInput: true,
							format: type.dateFormat + " HH:mm"
						});
				}
			},
			{ 
				field: "ExecuteAs", 
				title: "[resource_shortdisplayname[executeas]]", 
				width: 120,
				editor: function(container, options) {
					$('<input required name="' + options.field + '"/>')
						.appendTo(container)
						.kendoDropDownList({
							autoBind: false,
							dataTextField: "Id",
							dataValueField: "Id",
							dataSource: users
						});
				}
			}
		];

		grid.commands.push({name: "editArgs", text: "[resource_displayname[editargs]]", icon: "k-i-pencil"});
		grid.commands.push({name: "execute", text: "[resource_displayname[execute]]", icon: "k-i-play-sm"});
		grid.commands.push({name: "save", text: "[resource_displayname[save]]", icon: "k-i-save"});
		grid.commands.push({name: "destroy", text: "[resource_displayname[delete]]" , icon: "k-i-trash"});

		grid.dataBound = function () {
			$("button[name=save]", grid.gridElement).on("click", (e) => Scheduling.save(e, grid));
			$("button[name=destroy]", grid.gridElement).on("click", (e) => Scheduling.destroy(e, grid));
			$("button[name=editArgs]", grid.gridElement).on("click", (e)  => Scheduling.editArgs(e, grid));
			$("button[name=execute]", grid.gridElement).on("click", async (e) => await Scheduling.execute(e, grid));
		};

		grid.detailTemplate = "<div></div>";

		grid.detailExpand = async (e) => {
			var item = grid.dataItem($(e.masterRow));
			var componentContainer = $(".component[name=FlowInstanceManagement]", $("div", $(e.detailRow)));
			if(componentContainer.length === 0) {
				var flow = await api.get("Workflow/FlowDefinition(" + item.FlowId + ")?$select=InstanceReportingComponentName,Id");
				$("div", $(e.detailRow)).html($("[name=flowInstanceManagementComponent]").first().html());
				FlowInstanceManagement.init(app, $(".component[name=FlowInstanceManagement]", $("div", $(e.detailRow))), flow.Id, flow.InstanceReportingComponentName);
			}
		};

		await grid.init();
		$("button[name=create]", grid.gridElement).on("click", () => Scheduling.newScheduledTask(app, grid, flowDefinitions));
	},

	editArgs: async function(e, grid) {
		e.preventDefault();
		var task = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
		var argsEditor = null;
		var d = new Dialog({
			title: "[resource_displayname[editArgs]]",
			width: 800
		});
		d.template = $("script[name=editArgs]").html();
		d.events.save = async function (e) {
			task.save(e, function () { notification.success("[resource_displayname[ScheduledTaskSaved]]"); d.events.close(); });
		};
		d.init(() => {
			argsEditor = new MonacoEditor($("[name=executionArgs]", d.element)[0], { code: task.ExecutionArgs, language: "json", automaticLayout: true });
			argsEditor.onChange = (e) => task.ExecutionArgs = argsEditor.getValue();
			argsEditor.init();
			argsEditor.editor.layout();
		});
	},

	newScheduledTask: async function (app, grid, flowDefinitions) {
		var d = new Dialog({ title: "[resource_displayname[newscheduledtask]]", width: 620, height: 520 });
		d.template = $("[name=newScheduledTask]").html();
		var appRoles = (await api.get("AppSecurity/Role?$expand=Users&$filter=AppId eq " + app.Id)).value;
		var userIds = appRoles.map(r => r.Users).flat().map(r => r.UserId);
		var argsEditor = null;
		d.events.create = async function (e) {
			var newScheduledTask = {
				Name: $("[name=name]", d.element).val(),
				Description: $("[name=description]", d.element).val(),
				FlowId: $("[name=flowDefinition]", d.element).val(),
				AppId: app.Id,
				ExecuteAs: $("[name=executeas]", d.element).val(),
				NextExecution: (new Date($("[name=nextexecution]", d.element).val())).toISOString(),
				ExecutionArgs: argsEditor.getValue()
			};
			d.events.close();
			await api.add("Scheduling/ScheduledTask", newScheduledTask).then(() => {
				notification.success("[resource_displayname[added]]");
				grid.refresh();
			}).catch((err) => error(err));
		};
		d.init(async () => {
			$("[name=flowDefinition]", d.element).kendoDropDownList({ dataTextField: "Name", dataValueField: "Id", dataSource: flowDefinitions });
			$("[name=nextexecution]", d.element).kendoDateTimePicker({ value: new Date(), dateInput: true });
			$("[name=executeas]").kendoDropDownList({
				dataSource: { data: userIds }
			});
			argsEditor = new MonacoEditor($("[name=executionArgs]", d.element)[0], { code: "", language: "json", automaticLayout: true });
			argsEditor.init();
			grid.refresh();
		});
	},

	execute: async function(e, grid) {
		e.preventDefault();
		var task = grid.dataItem($(e.currentTarget).closest("tr"));
		await api.post("Scheduling/ScheduledTask(" + task.Id + ")/Execute?incrementNextExecution=false").then(() => {
			notification.success("[resource_displayname[executed]]");
		}).catch((err) => error(err));
	},

	save: async function (e, grid) {
		e.preventDefault();
		var task = grid.dataItem($(e.currentTarget).closest("tr"));
		var copy = JSON.parse(JSON.stringify(task));
		delete copy.Schedule;
		delete copy.type;
		delete copy.Flow;
		delete copy.ExecuteAs_input;
		if(typeof(copy.ScheduleInTicks) === 'string') {
			copy.ScheduleInTicks = parseInt(copy.ScheduleInTicks);
		}
		await api.put("Scheduling/ScheduledTask(" + copy.Id + ")", copy).then(() => {
			notification.success("[resource_displayname[saved]]");
			grid.refresh();
		}).catch((err) => error(err));
	},

	destroy: function (e, grid) {
		e.preventDefault();
		var task = grid.dataItem($(e.currentTarget).closest("tr"));
		task.destroy(e).then(() => {
			notification.success("[resource_displayname[deleted]]");
			grid.refresh();
		}).catch((err) => error(err));
	}
}

Shadows = {
    init: async function (app, container, observable) {
        app = app || session.app;
        container = container || $(".component[name=Shadows]");
        if (!observable)
            return;

        $("[name=colour]", container).kendoColorPicker({
            buttons: false,
            value: observable.get("shadows").split(" ")[3],
