SSOMetadata = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=SSOMetadata]");
        var swaggerDefinition = await api.get("../swagger/v1/swagger.json");
        var dataSource = await SSOMetadata.getDatasource();
        var grid = new GridWidget(container, { data: dataSource, pageSize: 1000, group: { field: "Category", dir: "asc"} });
        grid.editable = false;
        grid.columns = [
            { field: "Category", title: "[resource_displayname[context]]", width: 200 },
            { field: "DisplayName", title: "[resource_displayname[displayname]]", width: 200 },
            { field: "url", title: "[resource_displayname[url]]", template: "#:session.apiRoot##:Category#/#:DisplayName#" }
        ];

        grid.detailTemplate = $("script[name=metadataDetails]", container).first().html();
        grid.detailExpand = async function(e) {
            var container = $(e.detailRow);
            var meta = this.dataItem(e.masterRow);
            if($(".k-tabstrip", container).length == 0) {
                $("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });
                var editor = new MonacoEditor($("[name=rawJson]", container)[0], {
                    code: JSON.stringify(meta, null, '\t'),
                    language: "json",
                    automaticLayout: true
                });
                editor.init();
                await SSOMetadata.setupMetaPropertiesGrid(container, meta);
                await SSOMetadata.setupEndpoints(container, meta, swaggerDefinition.paths, app);
                await SSOMetadata.setupDependencies(container, meta);
            }
        };
        await grid.init();

    },

    getDatasource: async function() {
        var data = [];
        var allMeta = await api.get("Getmetadata");

        var contexts = allMeta.filter(i => i.UriBase && i.Name === "Security");
        contexts.forEach((context) => {
            var entities = context.Types.filter(t => t.IsEntity && t.HasEndpoint).sort((t1, t2) => t1.DisplayName > t2.DisplayName ? 1 : -1);
            entities.forEach((item) => {
                item.id = item.Category + '/' + item.DisplayName;
                item.testStatus = "loading";
                item.isUp = "loading";
                data.push(item);
            })
        });

        window.allMeta = data;;

        return data;
    },

    setupMetaPropertiesGrid: async function (container, meta) {
        var propertyGrid = new GridWidget($("[name=properties]", container), { data: meta.Properties, pageSize: 50 });
        propertyGrid.exports = false;
        propertyGrid.editable = false;
        propertyGrid.groupable = false;

        propertyGrid.columns = [
            { field: "Name", title: "[resource_displayname[name]]" },
            { field: "Type", title: "[resource_displayname[type]]" },
            { field: "ServerType", title: "[resource_displayname[servertype]]" },
            { field: "ServerTypeName", title: "[resource_displayname[servertypename]]" },
            { field: "Template", title: "[resource_displayname[template]]" },
            { field: "DisplayName", title: "[resource_displayname[displayname]]" },
            { field: "ShortDisplayName", title: "[resource_displayname[shortdisplayname]]" },
            { field: "Description", title: "[resource_displayname[description]]" },
            { field: "IsGeneric", title: "[resource_displayname[isgeneric]]", type: "boolean" },
            { field: "IsValueType", title: "[resource_displayname[isvaluetype]]", type: "boolean" },
            { field: "IsReadOnly", title: "[resource_displayname[isreadonly]]", type:"boolean" },
            { field: "IsRequired", title: "[resource_displayname[isrequired]]", type: "boolean" }
        ];
        await propertyGrid.init();
    },

    setupEndpoints: async function(container, meta, swaggerPaths, app) {
        var applicableEndpointKeys = Object.keys(swaggerPaths).filter(r => r.indexOf("/Api/" + meta.id) !== -1);
        var applicableEndpoints = applicableEndpointKeys.map(endpointURL => 
            SSOMetadata.getHttpMethods(swaggerPaths[endpointURL]).map(httpMethodName => ({
                "endpoint": endpointURL,
                "data": swaggerPaths[endpointURL][httpMethodName.toLowerCase()],
                "method": httpMethodName
            }))).flat();

        var endpointGrid = new GridWidget($("[name=endpoints]", container), { data: applicableEndpoints, pageSize: 20 });
        endpointGrid.groupable = false;
        endpointGrid.columns = [
            { field: "method", title: "[resource_displayname[methods]]", template: "#=method#", width: 80 },
            { field: "endpoint", title: "[resource_displayname[endpoint]]", template: "#=endpoint#" },
        ];
        endpointGrid.dataBound = function() {
            $("[name=explore]", endpointGrid.gridElement).on("click", (e) => SSOMetadata.explore(e, app, endpointGrid));
        };

        endpointGrid.commands.push({name: "explore", icon: "k-i-search", text: "[resource_displayname[explore]]" });

        await endpointGrid.init();
    },

    setupDependencies: async function(container, meta) {
        var foreignKeys = meta.Properties.filter(p => p.Name.endsWith("Id") && p.Name != "Id" &&  
            meta.Properties.filter(p2 => p2.Name == p.Name.substring(0, p.Name.length - 2) && p2.Type == "object").length > 0);

        foreignKeys.map(fk => {
            var object = meta.Properties.filter(p2 => p2.Name == fk.Name.substring(0, fk.Name.length - 2) && p2.Type == "object")[0];
            var serverTypeInformation = object.ServerType;
            var entity = window.allMeta.filter(metaEntry => metaEntry.ServerType.startsWith(serverTypeInformation))[0];
            fk.RelatedEntity = entity;
        });

        var dependsOnGrid = new GridWidget($("[name=dependson]", container), { data: foreignKeys, pageSize: 50 });
        dependsOnGrid.exports = false;
        dependsOnGrid.editable = false;
        dependsOnGrid.columns = [
            { field: "Name", title: "[resource_displayname[foreignkey]]" },
            { field: "Type", title: "[resource_displayname[type]]"},
            { field: "IsRequired", type:"boolean", title: "[resource_displayname[isrequired]]"},
            { field: "ServerType", title: "[resource_displayname[servertype]]"},
            { field: "RelatedEntity.id", title: "[resource_displayname[relatedentity]]"}
        ];
        dependsOnGrid.init();
    },

    explore: async function(e, app, endpointGrid) {
        e.preventDefault();
        var item = endpointGrid.dataItem($(e.currentTarget).closest("tr"));

        var exploreDialog = new Dialog({title: "[resource_displayname[explore]]", width: 1900, height: 805 });
        exploreDialog.init(async () => {
            var apiTesterComponent = await loadComponent(exploreDialog.element, "ApiTester");
            var endpointPath = item.endpoint.substring(item.endpoint.indexOf("/Api/")+5);
            if(item.data.parameters && item.data.parameters.filter(r => r.name == "queryOptions" && r.schema["$ref"].indexOf("ODataQueryOptions") !== -1).length > 0) {
                endpointPath += "?$top=10";
            }

            apiTesterComponent.init(app, $(".component[name=ApiTester]", exploreDialog.element), item.method, endpointPath);
        });
    },

    getHttpMethods: function(swaggerPathEntry) {
        return Object.keys(swaggerPathEntry).map(o => o.toUpperCase());
    }
};

