            TenantActivity.setupReportGeneration(d.element, model);
            kendo.bind(d.element, model);
        });
    },

    generateReport: async function(reportParams) {
        reportParams.start = reportParams.fromYear + "-" + reportParams.fromMonth + "-01";
        
        var end = reportParams.toYear + "-" + reportParams.toMonth + "-01";
        end = new Date(end);
        end.setMonth(end.getMonth() + 1);
        end.setDate(0);
        reportParams.end = end.toISOString().split('T')[0];

        reportParams.Data = await TenantActivity.getReportData(reportParams);
        var reportUrl = `Core/Template/Render?appId=${session.app.Id}&name=Test&culture=${session.culture}`;
        var report = await api.post(reportUrl, reportParams);

        var dialogConfig = { 
            name: "activityReport",
            title: "[resource_displayname[activityreport]]", 
            width: 1200, 
            height: 800,
            template: `
                <div class="k-toolbar">
                    <div class="btn-group btn-group-sm">
                        <button class="btn btn-primary" name="downloadReport">
                            <span class="k-icon k-svg-icon k-svg-i-save" aria-hidden="true"></span>
                            Download This Report
                        </button>
                    </div>
                </div>
                <div style="height: 730px; width: 1200px;" name="report"></div>`
        };

        var d = new Dialog(dialogConfig);
        d.events.downloadReport = () => TenantActivity.downloadReport(report);
        d.init();

        const iframe = document.createElement('iframe');
        iframe.srcdoc = report;
        iframe.style.width = "100%";
        iframe.style.height = "100%";
        iframe.style.border = "none";
        $("[name=report]", d.element).append(iframe);
    },

    setupReportGeneration: function(container, model) {
       var apps = [];
       model.tenant.apps.map(a => apps.push({ Id: a.Id, Name: `${a.Name} (${a.Domain})`}))

        $("[name=appId]", container)
            .kendoDropDownList({
                dataSource: apps,
                dataTextField: "Name",
			    dataValueField: "Id"
            }).data("kendoDropDownList");

        $("select[name=fromMonth]", container)
            .kendoDropDownList();

        $("select[name=fromYear]", container)
            .kendoDropDownList();

        $("select[name=toMonth]", container)
            .kendoDropDownList();

        $("select[name=toYear]", container)
            .kendoDropDownList();
    },

    getReportData: async function(reportParams) {
        var tenant = reportParams.tenant.Id;
        var filter = "$filter=TenantId eq '" + tenant + "' and Name eq 'User Activity (Daily)' and CreatedOn ge " + reportParams.start + " and CreatedOn le " + reportParams.end;

        var analytics = (await api.get(`Security/TenantAnalysis?${filter}&$format=json&$orderby=CreatedOn desc&$count=true`))
            .value
            .map((entry) => {
                return {
                    date: entry.CreatedOn.split('T')[0],
                    data: JSON.parse(entry.Value)
                };
            });

        var data = [];
        
        for(var i in analytics) {
            var entry = analytics[i];
            
            data.push({
                date: entry.date,
                users: entry.data.Users,
                apiCalls: entry.data.ApiCalls,
                pages: entry.data.Pages
            });
        }

        var users = [];
        var sessions = [];
        var pageHits = [];
        var apiCalls = [];

        var userIds = new Set();

        for(var i in data) {
            var row = data[i];
            
            for(var u in row.users) {
                var user = row.users[u];

                if (!userIds.has(user.User.Id)) {
                    users.push({ Id: user.User.Id, DisplayName: user.User.UserDisplayName, Email: user.User.UserEmail });
                    userIds.add(user.User.Id);
                }

                sessions.push({ Date: row.date, DisplayName: user.User.UserDisplayName, Email: user.User.UserEmail, SessionCount: user.Sessions, PageHits: user.PageRequests, ApiCalls: user.ApiRequests });
            }
            
            for(var p in row.pages) {
                var page = row.pages[p];
                pageHits.push({ Date: row.date, Page: page.Page, Hits: page.Hits, Sessions: page.Sessions });
            }
            
            for(var a in row.apiCalls) {
                var apiCall = row.apiCalls[a];
                apiCalls.push({ Date: row.date, Endpoint: apiCall.Endpoint, Hits: apiCall.Hits, Sessions: apiCall.Sessions });
            }
        } 

        return {
            Users: users,
            Sessions: sessions,
            PageHits: pageHits,
            ApiCalls: apiCalls
        };
    },

    downloadReport: async function(report) {
        const response = await fetch('Api/Core/Template/HtmlToPdf?name=Activity Report', {
            method: 'POST',
            headers: { 'Content-Type': 'text/plain' },
            body: report,
        });

        const pdfBlob = await response.blob();
        const url = window.URL.createObjectURL(pdfBlob);
        const link = document.createElement('a');
        link.href = url;
        link.download = 'Activity Report.pdf';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link); 
        window.URL.revokeObjectURL(url); 
    }
}

