    unpackContentFolder: async function (newApi, tenant, sourceAppId) {
        var app = await api.get("Core/App(" + sourceAppId + ")");

        try {
            var blob = await new Promise(function (resolve, reject) {
                var sourceReq = new XMLHttpRequest();
                sourceReq.open("GET", window.location.protocol + "//" + app.Domain + "/Api/DMS/Content" + "?t=" + session.token, true);
                sourceReq.setRequestHeader("Authorization", "bearer " + session.token);
                sourceReq.responseType = "blob";
                sourceReq.onload = function (oEvent) {
                    if (this.readyState === 4 && this.status >= 200 & this.status <= 300) {
                        resolve(this.response);
                    } else {
                        reject(this.status);
                    }
                };
                sourceReq.send();
            });
        } catch(error) {
            console.log(error);
            notification.error('[resource_displayname[failedToPackDmsContent]]');
        }

        try {
            await new Promise(function (resolve, reject) {
                var destReq = new XMLHttpRequest();
                destReq.open("PUT", newApi.apiRoot + "DMS/?unpack" , true);
                destReq.setRequestHeader("Authorization", "bearer " + newApi.token);
                destReq.setRequestHeader("Content-Type", "application/zip");
                destReq.onload = function (oEvent) {
                    if (this.readyState === 4 && this.status >= 200 && this.status <= 300) {
                        resolve(this.response);
                    } else {
                        reject(this.status);
                    }
                };
                destReq.send(blob);
            });
        } catch(error) {
            console.log(error);
            notification.error('[resource_displayname[failedToUnpackDmsContent]]');
        }

        try {
            var blob = await new Promise(function (resolve, reject) {
                var sourceReq = new XMLHttpRequest();
                sourceReq.open("GET", "/Api/DMS/CRM/" + tenant.Id + "/Theme/Content" + "?t=" + session.token, true);
                sourceReq.setRequestHeader("Authorization", "bearer " + session.token);
                sourceReq.responseType = "blob";
                sourceReq.onload = function (oEvent) {
                    if (this.readyState === 4 && this.status >= 200 & this.status <= 300) {
                        resolve(this.response);
                    } else {
                        reject(this.status);
                    }
                };
                sourceReq.send();
            });
        } catch(error) {
            console.log(error);
            notification.error('[resource_displayname[failedToPackThemeContent]]');
        }

        try {
            await new Promise(function (resolve, reject) {
                var destReq = new XMLHttpRequest();
                destReq.open("PUT", newApi.apiRoot + "DMS/?unpack" , true);
                destReq.setRequestHeader("Authorization", "bearer " + newApi.token);
                destReq.setRequestHeader("Content-Type", "application/zip");
                destReq.onload = function (oEvent) {
                    if (this.readyState === 4 && this.status >= 200 && this.status <= 300) {
                        resolve(this.response);
                    } else {
                        reject(this.status);
                    }
                };
                destReq.send(blob);
            });
        } catch(error) {
            console.log(error);
            notification.error('[resource_displayname[failedToUnpackThemeContent]]');
        }
    },

    linkAdmins: async function(app, newApi){
