    createBuyerAdminAccount: async function (newApi, appName) {
        var ssoUser = await newApi.register({
            DisplayName: appName + ".admin",
            Email: appName.replaceAll(' ', '') + ".admin@' + (newApi.app.Domain || location.hostname)",
            Password: Guid().replaceAll("-", "") + "A!",
            Culture: newApi.app.DefaultCultureId,
            PhoneNumber: "",
            AppId: newApi.app.Id
        });
        var userId = ssoUser.id;
        var appInfo = await newApi.get("Core/App(" + newApi.app.Id + ")?$select=ConfigJson");
        /* b2b onboarding */
        var config = JSON.parse(appInfo.ConfigJson);
        var rootBucketId = config.B2B.RootBucket;
        var buyerAdminRoleId = (await newApi.get("B2B/BucketRole?$filter=Bucket/ParentId eq " + rootBucketId + " and (contains(Role/Name, 'Buyer') or contains(Role/Name, 'Debtor'))")).value[0].RoleId;
        var userIsBuyerAdmin = (await newApi.get(`B2B/B2BUserRole?$filter=UserId eq '${userId}' and RoleId eq ${buyerAdminRoleId}`)).value.length > 0;
        if(!userIsBuyerAdmin)
            await newApi.post("B2B/B2BUserRole", {
                UserId: userId,
                RoleId: buyerAdminRoleId
            }).catch((err) => error(err));
        
        /* core onboarding */
        var coreBuyerRoleId = (await newApi.get("AppSecurity/Role?$filter=contains(Name, 'Buyer') and AppId eq " + newApi.app.Id)).value[0].Id;
        await newApi.post("AppSecurity/UserRole", {
            UserId: userId,
            RoleId: coreBuyerRoleId
        }).catch((err) => error(err));

        var coreAdminRoleId = (await newApi.get("AppSecurity/Role?$filter=contains(Name, 'Admin') and AppId eq " + newApi.app.Id)).value[0].Id;
        await newApi.post("AppSecurity/UserRole", {
            UserId: userId,
            RoleId: coreAdminRoleId
        }).catch((err) => error(err));

        notification.success("[resource_displayname[adminusercreated]]");

        return ssoUser;
    },

    copyWorkflowsTriggersAndSchedules: async function(newApi, userId, sourceAppId) {
        var transactionsReceivedEvents = (await api.get(`Workflow/WorkflowEvent?$expand=Flow&$filter=Type eq 'Core/File' and EventContext eq 'App(${sourceAppId})/DMS(File_Created)/data/transactions/received'`)).value;
        var masterdataReceivedEvents = (await api.get(`Workflow/WorkflowEvent?$expand=Flow&$filter=Type eq 'Core/File' and EventContext eq 'App(${sourceAppId})/DMS(File_Created)/data/masterdata/received'`)).value;
        var scheduledTasks = (await api.get(`Scheduling/ScheduledTask?$filter=AppId eq ${sourceAppId}&$expand=Flow`)).value;
        var appWorkflows = (await api.get(`Workflow/FlowDefinition?$filter=AppId eq ${newApi.app.Id}`)).value;

        for(var event of transactionsReceivedEvents) {
            var matchedFlow = appWorkflows.filter(wf => wf.Name == event.Flow.Name)[0];

            if(matchedFlow) {
                await newApi.post('Workflow/WorkflowEvent', {
                    Type: "Core/File",
                    EventContext: "App(" + newApi.app.Id + ")/DMS(File_Created)/data/transactions/received",
                    FlowId: matchedFlow.Id,
                    ExecuteAs: userId
                });
            }
        }

        for(var event of masterdataReceivedEvents) {
            var matchedFlow = appWorkflows.filter(wf => wf.Name == event.Flow.Name)[0];

            if(matchedFlow) {
                await newApi.post('Workflow/WorkflowEvent', {
                    Type: "Core/File",
                    EventContext: "App(" + newApi.app.Id + ")/DMS(File_Created)/data/masterdata/received",
                    FlowId: matchedFlow.Id,
                    ExecuteAs: userId
                });
            }
        }

        for(var task of scheduledTasks) {
            var matchedFlow = appWorkflows.filter(wf => wf.Name == task.Flow.Name)[0];

            if(matchedFlow) {
                await newApi.post('Scheduling/ScheduledTask', {
                    AppId: newApi.app.Id,
                    FlowId: matchedFlow.Id,
                    Name: task.Name,
                    Description: task.Description,
                    ExecutionArgs: task.ExecutionArgs,
                    ScheduleInTicks: task.ScheduleInTicks,
                    ExecuteAs: userId,
                    NextExecution: task.NextExecution
                });
            }
        }
    },

