    linkAdminsToRootBucket: async function (newApi, rootBucketId) {
        var bucketAdminRole = (await newApi.get("B2B/BucketRole?$filter=BucketId eq " + rootBucketId + " and contains(Role/Name, 'Bucket Admins')")).value[0];
