        var bucketAdminRoleId = bucketAdminRole.RoleId;
        for (let i = 0; i < admins.value.length; i++) {
            var adminEntry = admins.value[i];
            await newApi.post("B2B/B2BUserRole", { UserId: adminEntry.UserId, RoleId: bucketAdminRoleId });
        }
    },

    createSourceSystem: async function (newApi, rootBucketId, tenant){
        var systemExists = await newApi.get("B2B/System?$filter=Id eq '" + tenant.Name + "'");
        if (systemExists.value.length == 0) {
            await newApi.post("B2B/System", {
                Name: tenant.Name,
                Description: tenant.Name,
                Id: tenant.Name
            });
        }
        await newApi.post("B2B/BucketSystem", {BucketId: rootBucketId, SystemId: tenant.Name});
    },

    setupConfig: async function (d, tenant, newApi) {
        var sourceApp = await api.get("Core/App(" + d.data.SourceAppId + ")");
        var config = JSON.parse(sourceApp.ConfigJson);
        var calendar = (await api.get("Scheduling/Calendar?$filter=AppId eq " + newApi.app.Id)).value[0];
