                await newApi.put("Core/App(" + newApi.app.Id + ")", newApi.app)
                    .catch((err) => error(err));
            }).catch((err) => error(err));
        }
        
        config.B2B.SourceSystem = tenant.Name;
        config.B2B.TransactionSource = tenant.Name;
        var domainName = newApi.app.Domain.split(".")[0];
        config.Deployment = {\r\n            "Targets": [],\r\n            "DMS": [\r\n                "Content",\r\n                "Content/Flags",\r\n                "Content/Slideshow"\r\n            ],\r\n            "TenantId": tenant.Id\r\n        },\r\n        newApi.app.ConfigJson = JSON.stringify(config, null, 4);
        await api.put("Core/App(" + newApi.app.Id + ")", newApi.app);
    },
}

