TenantManagement = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=TenantManagement]");
        
        api.addToMetaCache([
            {
                "Name": "Security",
                "Types": [
                    [meta[Security/Tenant]]
                ]
            },
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Country]]
                ]
            }
        ]);

        var tenantData = await model.getDatasource({endpoint: "Security/Tenant"});
        var tenantGrid = new GridWidget(container, tenantData);
        tenantGrid.groupable = false;
        tenantGrid.filterable = true;
        tenantGrid.editable = true;
        tenantGrid.detailTemplate = $("[name=tenantDetails]", container).first().html();
        tenantGrid.columns = [
            { field: "Id", title: "[resource_shortdisplayname[Id]]" },
            { field: "Name", title: "[resource_shortdisplayname[Name]]" },
            { field: "Description", title: "[resource_shortdisplayname[Description]]" },
        ];
        tenantGrid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" });
        tenantGrid.commands.push({ name: "remove", icon: "k-i-trash", text: "[resource_displayname[remove]]" });
        tenantGrid.toolbar = `<button class="btn btn-sm btn-primary" name='add'><span class='k-icon k-i-plus'></span>[resource_displayname[add]]</button>`;
        tenantGrid.dataBound = function (e) {
            $("[name=save]", tenantGrid.gridElement).off("click").on("click", (e) => TenantManagement.save(e, tenantGrid));
            $("[name=remove]", tenantGrid.gridElement).off("click").on("click", (e) => TenantManagement.openRemoveDialog(container, e, tenantGrid));
        };
        tenantGrid.detailExpand = async (e) => {
            if ($(".k-tabstrip", $(e.detailRow)).length > 0) {
                return;
            }

            var tenantContainer = $(e.detailRow);
            var tenant = tenantGrid.dataItem($(e.masterRow).closest("tr"));
            $("[name=tabs]", $(e.detailRow)).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });

            var apps = await loadComponent($(".tab[name=apps]", tenantContainer), "TenantAppManagement");
            apps.init(app, $(".component[name=TenantAppManagement]", $(".tab[name=apps]", tenantContainer)), tenant);

            var analytics = await loadComponent($("[name=analytics]", tenantContainer), "PlatformUsage");
            analytics.init({
                Config: app.Config,
                TenantId: tenant.Id
            }, $(".tab[name=analytics]", tenantContainer));

            var activity = await loadComponent($("[name=activity]", tenantContainer), "TenantActivity");
            activity.init(app, $("[name=activity]", tenantContainer), tenant);
        };

        await tenantGrid.init();

        $("[name=add]", container).off("click").on("click", (e) => TenantManagement.newTenant(e, tenantGrid));
    },

    save: async function (e, grid) {
        e.preventDefault();
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        await api.update("Security/Tenant('" + item.Id + "')").then(async () => {
            notification.success("[resource_displayname[saved]]");
        }).catch((err) => error(err));
    },

    openRemoveDialog: async function(container, e, grid) {
        var dialog = new Dialog({
            width: 600,
            height: 'auto',
            title: '[resource_displayname[deletetenant]]?'
        });
        var tenant = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));

        dialog.template = $('[name=delete-tenant-template]', container).html();

        
        dialog.events.confirm = async () => {
            var deleteRootBucket = $('[name=delete-root-bucket]', dialog.element).is(':checked');
            var deleteClientCrmFolder = $('[name=delete-client-crm-folder]', dialog.element).is(':checked');

            var apps = (await api.get(`Core/App?$filter=TenantId eq '${tenant.Id}'`)).value;

            if(apps.length > 0) {
                notification.error('[resource_displayname[tenantHasAppsCannotDelete]]');
                return;
            }

            if(deleteRootBucket)
                await TenantManagement.deleteTenantRootBucket(tenant);

            if(deleteClientCrmFolder)
                await TenantManagement.deleteClientCrmFolder(tenant);
            
            await TenantManagement.deleteTenantApps(tenant);
            await TenantManagement.remove(e, grid);
            
            dialog.events.close();

            grid.refresh();
        };

        dialog.init();
    },

    deleteClientCrmFolder: async function(tenant) {
        var crmFolders = (await api.get(`Core/Folder?$filter=AppId eq ${session.app.Id} and Path eq 'crm/${tenant.Id.toLowerCase()}'`)).value;
        var clientFolders = (await api.get(`Core/Folder?$filter=AppId eq ${session.app.Id} and Path eq 'clients/${tenant.Id.toLowerCase()}'`)).value;

        if(crmFolders.length > 0)
            for(var folder of crmFolders)
                await api.file.destroy(folder.Path);
                
        if(clientFolders.length > 0)
            for(var folder of clientFolders)
                await api.file.destroy(folder.Path);
    },

    deleteTenantRootBucket: async function(tenant) {
        // Transactions cleardown.
        var tenantSystem = (await api.get(`B2B/System?$filter=Id eq '${tenant.Id}'`)).value;
        if(tenantSystem.length == 0) {
            notification.error("[resource_displayname[tenantSourceSystemNotFound]]");
            notification.info("[resource_description[tenantSourceSystemNotFound]]");
            return;
        }

        await api.destroy(`B2B/Transactions/ClearDown?sourceSystemId=${tenant.Id}`);

        // Masterdata cleardown.
        var buckets = (await api.get(`B2B/Bucket?$filter=Path eq '${tenant.Id}'`)).value;
        if(buckets.length == 0) {
            notification.info('[resource_displayname[rootBucketNotFound]]');
            return;
        }

        var rootBucketId = buckets[0].Id;
        notification.info('[resource_displayname[clearingDownMasterdata]]');
        await api.post(`B2B/Bucket/ClearDown?rootBucketId=${rootBucketId}`);

        // Delete root bucket.
        await api.destroy(`B2B/Bucket(${rootBucketId})`);
    },
    
    remove: async function (e, grid) {
        e.preventDefault();
        var item = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
        await api.destroy("Security/Tenant('" + item.Id + "')").then(async () => {
            notification.success("[resource_displayname[tenantDeleted]]");
            grid.refresh();
        }).catch((err) => error(err));
    },

    newTenant: async function (e, tenantGrid) {
        e.preventDefault();
        var validator = null;
        var newTenantDialog = new Dialog({
            width: 600,
            height: "auto",
            title: "[resource_displayname[newtenant]]"
        });
        newTenantDialog.template = $("[name=newTenantDialog]").html();
        newTenantDialog.events.create = async function (e) {
            if (!validator.validate()) {
                return;
            }

            var tenant = {
                Id: $("[name=name]", newTenantDialog.element).val(),
                Name: $("[name=name]", newTenantDialog.element).val(),
                Description: $("[name=description]", newTenantDialog.element).val(),
                CreatedOn: (new Date()).toISOString(),
                LastUpdated: (new Date()).toISOString(),
                CreatedBy: session.user,
                LastUpdatedBy: session.user,
            };

            await api.add("Security/Tenant", tenant).then(async () => {
                notification.success("[resource_displayname[added]]");
                tenantGrid.refresh();
            }).catch((err) => error(err));
            
            newTenantDialog.events.close();
        };
        newTenantDialog.init();
       
        validator = newTenantDialog.element.kendoValidator().data("kendoValidator");
    },

    deleteTenantApps: async function(tenant) {
        var apps = (await api.get(`Core/App?$filter=TenantId eq '${tenant.Id}'`)).value;

        for(var app of apps)
            await api.destroy(`Core/App(${app.Id})`);
    }
}

