    getDataSource(url) {
        return new kendo.data.DataSource({
            transport: {
                read: { 
                    url: api.apiRoot + url, 
                    dataType: "json",
                    type: "GET",
                    beforeSend: function(req) {
                        req.setRequestHeader("Authorization", "bearer " + api.token);
                    }
                }
            },
            pageSize: 50,
            schema: {
                data: (response) => response,
                total: (response) => response.length
            }
        });;
    },

    save: async function(themeGrid, themesDMSPath) {
        await api.put(themesDMSPath, themeGrid.dataSource().data()).then(() => {
            notification.success("[resource_displayname[saved]]");
            themeGrid.refresh();
        }).catch((err) => error(err));
    },
    
    addTheme: function (themeGrid, themesDMSPath) {
        var model = kendo.observable({ name: "", theme: JSON.parse(JSON.stringify(session.app.Config.Themes.Default)) });
        var addThemeDialog = new Dialog({ title: "[resource_displayname[addtheme]]" });
        addThemeDialog.template = $("[name=addThemeDialog]").html();
        addThemeDialog.events.confirm = async function () {
            themeGrid.dataSource().insert(0, model);
            await ThemeList.save(themeGrid, themesDMSPath);
            addThemeDialog.events.close();
        };
        addThemeDialog.init(() => {  
            kendo.bind(addThemeDialog.element, model);  
        });
    },

    editFiles: async function (e, app, clientEntry) {
        var editFileDialog = new Dialog({ title: "[resource_displayname[edittheme]]", width: 1310, height: 410 });
        editFileDialog.init(async () => {
            await loadComponent(editFileDialog.element, "ClientFiles", (ClientFiles) => {
                ClientFiles.init(app, editFileDialog.element, clientEntry);
                $("[name=confirm]", editFileDialog.element).on("click", function (e) { editFileDialog.events.close(); });
            });
        });
    },

    editTheme: async function (e, app, themesDMSPath, themeGrid) {
        var themeEntry = themeGrid.dataItem($(e.currentTarget).closest("tr"));
        var editThemeDialog = new Dialog({ title: "[resource_displayname[edittheme]]", width: 1100, height: 750 });
        editThemeDialog.template = $("[name=editThemeDialog]").html();
        editThemeDialog.events.save = async function() {
            themeEntry.theme = ThemeBuilder.build($(".component[name=ThemeBuilder]", editThemeDialog.element));
            await ThemeList.save(themeGrid, themesDMSPath);
            editThemeDialog.events.close();
        };
        editThemeDialog.init(async () => {
            var c = await loadComponent($("[name=themeContent]", editThemeDialog.element), "ThemeBuilder");
            c.init(app, $(".component[name=ThemeBuilder]", editThemeDialog.element), themeEntry.theme);
        });
    },

    removeTheme: async function (e, themeGrid, themeEntry) {
        themeGrid.kendoObject.dataSource.remove(themeEntry);
    }
}

TopNav = {
	init: function(app, container, page) {
        app = app || session.app;
        container = container || $(".component[name=TopNav]");
        page = page || session.page;
		var query = "ContentManagement/Page?$filter=AppId eq " + session.app.Id + " and ParentId eq null&$orderby=Order asc&$expand=PageInfo,Pages($orderby=Order asc;$expand=PageInfo,Pages($orderby=Order asc;$expand=PageInfo))";
		api.get(query)
			.then(function(pages) {
				var menu = $("ul[name=menu]", container);
				var filteredPages = pages.value.filter(page => page.ShowOnMenus == true);
				TopNav.generateNavMenu(menu, filteredPages);
			});
	},

	generateNavMenu: function(nav, pages) {
		for(var i = 0; i < pages.length; i++) {
			var page = pages[i];
			var visibleChildren = TopNav.getVisibleChildPages(page);

			if(visibleChildren.length > 0)
				TopNav.generateNavDropdown(nav, page, visibleChildren)
			else
				TopNav.generateNavItem(nav, page);
		}
	},

	generateNavItem: function(nav, page) {
		var navItem = $('<li class="' + TopNav.itemClass(page, false) + '"></li>');
		navItem.append($('<a href="/' + page.Path + '" class="' + TopNav.linkClass(page, false) + '">' + TopNav.titleOf(page) + '</a>'));
		nav.append(navItem);
	},

	generateNavDropdown: function(nav, page, children) {
		var navItem = $('<li class="' + TopNav.itemClass(page, true) + '"></li>');
		navItem.append($('<a href="/' + page.Path + '" class="nav-link dropdown-toggle ' + (TopNav.isCurrentPage(page, true) ? 'active' : '') +'" aria-expanded="false">' + TopNav.titleOf(page) + '</a>'));
		var dropdown = $('<ul class="dropdown-menu"></ul>');
		for(var i = 0; i < children.length; i++) {
			var item = children[i];
			TopNav.generateNavDropdownItem(dropdown, item);
		}
		navItem.append(dropdown);
		nav.append(navItem);
	},

	generateNavDropdownItem: function(dropdown, page) {
		var navItem = $('<li></li>');
		navItem.append($('<a href="/' + page.Path + '" class="' + TopNav.linkClass(page, true) + '">' + TopNav.titleOf(page) + '</a>'));
		dropdown.append(navItem);
	},

	getVisibleChildPages: function(page) {
		var culture = ($("html").attr("lang")) ? $("html").attr("lang") : "";
		var selectedPageInfos = page.Pages.map(p => TopNav.getCurrentPageInfoTitle(p, culture));
		var sortedPages = selectedPageInfos.map(function (spi){ 
			var firstMatchingPage = page.Pages.filter(function (p){ 
				var pageHasMatchingPageInfo = p.PageInfo.filter(function (pi){ 
					return pi.Title == spi;
				}).length > 0;
				return pageHasMatchingPageInfo;
			})[0];
			return firstMatchingPage;
		});

		return sortedPages.filter(function(child) {
			return child.ShowOnMenus == true;
		});
	},

	getCurrentPageInfoTitle: function(page, culture) {
		var matchingPageInfos = page.PageInfo.filter(function(pi){
			return pi.CultureId == culture;
		});

		if(matchingPageInfos.length > 0)
			return matchingPageInfos[0].Title;

		return page.PageInfo.filter(function(pi){
			return pi.CultureId == "";
		})[0].Title;
	},

	createItem: function(page, parentElement, dropdown = false) {
		if(page.Path === null)
			page.Path = "";

		var dropdownNode = $("<ul class='dropdown-menu'></ul>");

		var culture = ($("html").attr("lang")) ? $("html").attr("lang") : "";
		var selectedPageInfos = page.Pages.map(p => TopNav.getCurrentPageInfoTitle(p, culture));
		var sortedPages = selectedPageInfos.map(function (spi){ 
			var firstMatchingPage = page.Pages.filter(function (p){ 
				var pageHasMatchingPageInfo = p.PageInfo.filter(function (pi){ 
					return pi.Title == spi;
				}).length > 0;
				return pageHasMatchingPageInfo;
			})[0];
			return firstMatchingPage;
		});

		for(var i in sortedPages) {
			if(sortedPages[i].ShowOnMenus) {
				TopNav.createItem(sortedPages[i], dropdownNode, (sortedPages.length > 1)); 
			}
		}

		parentElement.append($("<li data-id='" + page.Id + "' class='" + '' + "'></li>"));
		var thisNode = $("li[data-id=" + page.Id + "]", parentElement);

		thisNode.append("<a href='/" + page.Path + "'>" + TopNav.titleOf(page) + "</a>");

		if($("li", dropdownNode).length > 0) {
			thisNode.append(dropdownNode);
		}
	},

	titleOf: function(page) {
		if(!page.PageInfo || page.PageInfo.length === 0)
			return page.Name;

		var culture = ($("html").attr("lang")) ? $("html").attr("lang") : "";
		var matchingPageInfos = page.PageInfo.filter(function(pi){
			return pi.CultureId == culture;
		});

		if(matchingPageInfos.length > 0)
			return matchingPageInfos[0].Title;

		var defaultPageInfo = page.PageInfo.filter(function(pi){
			return pi.CultureId == "";
		})[0];

		return defaultPageInfo ? defaultPageInfo.Title : page.Name;
	},

	itemClass: function(page, dropdown = false) {
		var isCurrentPage = TopNav.isCurrentPage(page, false);

		if(dropdown == true)
			return isCurrentPage
				? 'nav-item dropdown active'
				: 'nav-item dropdown';
		return isCurrentPage
			? 'nav-item active'
			: 'nav-item';
	},

	linkClass: function(page, dropdown) {
		var isCurrentPage = TopNav.isCurrentPage(page, false);
		if(dropdown == true)
			return isCurrentPage ? 'dropdown-item active' : 'dropdown-item';
		return isCurrentPage ? 'nav-link active' : 'nav-link';
	},

	isCurrentPage: function(page, isParent = false) {
		var currentPath = (session.page && session.page.Path) ? session.page.Path : '';
		var pagePath = page.Path || '';

		if(isParent == true)
			return pagePath !== '' && currentPath.indexOf(pagePath + '/') === 0;

		return currentPath === pagePath;
	}
};

UserProfile = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=UserProfile]");
        if (session.user) {
            $("[name=userPrefs]", container).css("cursor", "pointer");
            $("[name=userPrefs]", container).on("click", () => UserProfile.showProfile(app));
        }
        $("a[name=logout]", container).on("click", async (e) => {
            e.preventDefault();
            await api.logout();
            window.location.href = '/';
        }); 
    },

    showProfile: async function ( app) {
        var model = null;
        var SSOUser = await api.get("Security/SSOUser/Me()");
        var CoreUser = await api.get("Core/User/Me()");
        var d = new Dialog({ title: "[resource_displayname[edituserprofile]]" });
        d.template = $("[name=userProfileDialog]").html();
        d.events.confirm = async  () => await UserProfile.updateProfile(model.toJSON());
        d.events.updatePassword = async function () {
            d.events.close();
            await UserProfile.resetPassword();
        };
        d.init(async () => {
            var cultures = (await api.get("Core/App(" + app.Id + ")?$expand=Cultures($expand=Culture)")).Cultures;
            model = new kendo.data.ObservableObject({
                Id: SSOUser.Id,
                Email: SSOUser.Email,
                DisplayName: SSOUser.DisplayName,
                PhoneNumber: SSOUser.PhoneNumber,
                DefaultCultureId: CoreUser.DefaultCultureId
            });
            $("input[name=culture]", d.element).kendoDropDownList({
                dataTextField: "Culture.Name",
                dataValueField: "CultureId",
                height: 310,
                dataSource: {
                    data: cultures
                }
            }).data("kendoDropDownList");
            kendo.bind($(d.element), model);
            $(d.element).data("model", model);
        });
    },

    resetPassword: async function () {
        var model = null;
        var d = new Dialog({ title: "[resource_displayname[resetpassword]]" });
        d.template = $("[name=forgotPasswordDialog]").html();
        d.events.confirm = async function () {
            UserProfile.changePassword(model.toJSON());
        };
        d.init(() => {
            model = new kendo.data.ObservableObject({
                OldPassword: "",
                NewPassword: "",
                ConfirmPassword: ""
            });
            kendo.bind($(d.element), model);
            $(d.element).data("model", model);
        });
    },

    changePassword: async function (model) {
        await api.update("Account/ChangePassword", model).then(() => {
            notification.success("[resource_displayname[PasswordChanged]]");
        }).catch((err) => error(err));
    },

    updateProfile: async function (model) {
        var SSOUserModel = {
            Id: model.Id,
            Email: model.Email,
            DisplayName: model.DisplayName,
            PhoneNumber: model.PhoneNumber
        };
        var CoreUserModel = {
            Id: model.Id,
            Email: model.Email,
            DisplayName: model.DisplayName,
            DefaultCultureId: (model.DefaultCultureId) ? model.DefaultCultureId : ""
        };
        var B2BUserModel = {
            Id: model.Id,
            EmailAddress: model.Email,
            DisplayName: model.DisplayName
        };
        await api.update("Security/SSOUser('" + SSOUserModel.Id + "')", SSOUserModel).then(async () => {
            await api.update("Core/User('" + CoreUserModel.Id + "')", CoreUserModel).then(async () => {
                await api.update("B2B/B2BUser('" + B2BUserModel.Id + "')", B2BUserModel).then(async () => {
                    $("span[name=userPrefs]").html(SSOUserModel.DisplayName);
                    notification.success("[resource_displayname[UserUpdated]]");
                }).catch((err) => error(err));
            }).catch((err) => error(err));
        }).catch((err) => error(err));
    }
}

WorkflowManagement = {
	init: async function (app, container, process) {
		app = app || session.app;
		container = container || $('.component[name=WorkflowManagement]');

		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Workflow/FlowDefinition]]
				]
			}
		]);
		var config = {
			endpoint: "Workflow/FlowDefinition",
			odataAppend: "?$filter=" + (process ? "AppId eq " + app.Id + " and ProcessId eq " + process.Id : "AppId eq " + app.Id)
		};
		var flowDefinitions = await model.getDatasource(config);
		await WorkflowManagement.setupGrid(app, container, flowDefinitions, process);
		if(!window.knownTypes) { window.knownTypes = await api.get('GetMetadata'); }
	},

	setupGrid: async function(app, container, flowDefinitions, process) {
		var grid = new GridWidget(container, flowDefinitions);
		grid.toolbar = "<button name='add' class='btn btn-primary'><span class='k-icon k-svg-icon k-svg-i-plus'></span>[resource_shortdisplayname[new]]</button>";
		grid.groupable = false;
		grid.scrollable = false;
		grid.pageable = false;
		// grid.commandWidth = 120;
		grid.columns = [
			{ field: 'Name', title: "[resource_displayname[name]]" },
			{ field: 'Description', title: "[resource_displayname[description]]" }, 
			{ field: 'CreatedBy', title: "[resource_displayname[createdby]]" }, 
			{ field: 'CreatedOn', format: "{0:" + type.dateFormat + "}", title: "[resource_displayname[created]]" }, 
			{ field: 'LastUpdatedBy', title: "[resource_displayname[lastupdatedby]]" }, 
			{ field: 'LastUpdated', format: "{0:" + type.dateFormat + "}", title: "[resource_displayname[lastupdated]]" }, 
			{ field: 'InstanceReportingComponentName', title: "[resource_displayname[instancereportingcomponentname]]" },
			{ field: 'Id', template: "<a href='/Admin/WorkflowDesigner?id=#:Id#'>[resource_displayname[edit]]</a>", name: "edit", icon: "k-i-edit", title: " " }
		];
		grid.commands.push();
		grid.commands.push({name: "save", icon: "k-i-save", text: "[resource_displayname[save]]"});
		grid.commands.push({name: "run", icon: "k-i-play", text: "[resource_displayname[run]]"});
		grid.commands.push({name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]"});
		grid.detailTemplate = kendo.template($("script[name=FlowDetails]", container).html());
		grid.dataBound = function() {
			$('[name=delete]', grid.gridElement).on("click", (e) => WorkflowManagement.deleteFlow(e, grid));
			$('[name=run]', grid.gridElement).on("click", (e) => WorkflowManagement.runFlow(e, grid));
			$('[name=save]', grid.gridElement).on("click", (e) => WorkflowManagement.save(e, grid));
		};
		grid.detailExpand = async function(e) {
			var definition = grid.dataItem(e.masterRow);
			if (definition.ReportingComponentName) {
				$("[name=tabs] > ul", container).append("<li>[resource_displayname[report]]</li>");
				$("[name=tabs]", container).append("<div class='tab' name='report'></div>");
			}
			$("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });
			if (definition.ReportingComponentName) {
				var reportTab = $(".tab[name=report]", container);
				var reportComponent = await loadComponent(reportTab, definition.ReportingComponentName);
				await reportComponent.init(app, $(".component[name=" + definition.ReportingComponentName + "]"), definition);
			}
			if ($(".tab[name=executions]", e.detailRow)[0].childElementCount === 0) {
				$(".tab[name=executions]", e.detailRow).html($("[name=flowInstanceManagementComponent]").first().html());
				FlowInstanceManagement.init(app, $(".component[name=FlowInstanceManagement]", $("[name=executions]", e.detailRow)), definition.Id, definition.InstanceReportingComponentName);
			}
		};
		await grid.init();
		$('[name=add]', grid.gridElement).on('click', { grid: grid }, async (e) => await WorkflowManagement.addFlow(e, process, grid, app));
	},


	addFlow: async function (e, process, grid, app) {
		e.preventDefault();
		var roles = await api.get("AppSecurity/Role?$filter=AppId eq " + app.Id);
		var d = new Dialog({ title: "[resource_displayname[NewFlow]]" });
		d.template = $("[name=newFlow]").html();
		d.events.add = async function () {
			var flow = {
				"Name": $("input[name=Name]", d.element).val(),
				"AppId": app.Id,
				"Description": "[resource_displayname[NewFlow]]",
				"ReportingComponentName": null,
				"InstanceReportingComponentName": null,
				"DefinitionJson": JSON.stringify({
					"Name": $("input[name=Name]", d.element).val(),
					"RequiredRoles": $("input[name=RequireRoles]:checked", d.element)
						.map((i, o) => o.value)
						.toArray()
						.join(","),
					"Links": [],
					"Activities": [{
						"$type": "Core.Objects.Workflow.Activities.Start, Core.Objects",
						"AuthToken": null,
						"Data": null,
						"Ref": "Start",
						"State": 0
					}
					]
				})
			};
			if (process)
                flow.ProcessId = process.Id;

			await api.add('Workflow/FlowDefinition', flow).then(() => {
				d.events.close();
				grid.refresh();
			}).catch((err) => error(err));
		};
		d.init(() => {
			var roleSet = $('[name=roles]', d.element);
			roleSet.html("");
			for (var i in roles.value) {
				var role = roles.value[i];
				roleSet.append('<li><input type="checkbox" name="RequireRoles" value="' + role.Name + '" /><label>' + role.Name + '</label></li>');
			}
		});

	},

	runFlow: function (e, grid) {
		e.preventDefault();
		var item = grid.dataItem($(e.currentTarget).closest("tr"));
		delete item.type;
		var flow = new Flow(item);
		flow.run(false);
	},

	deleteFlow: function (e, grid) {
		e.preventDefault();
		var item = grid.dataItem($(e.currentTarget).closest("tr"));

		var d = new ConfirmDialog({
			question: "[resource_description[thiscannotbeundone]]",
			confirm: "[resource_displayname[confirm]]",
			width: 400,
			height: 200,
			title: "[resource_description[areyousure]]"
		});
		d.events.confirm = async function (e) {
			e.preventDefault();
			await api.destroy("Workflow/FlowDefinition(" + item.Id + ")").then(() => {
				notification.success("[resource_description[deleted]]");
				grid.refresh();
				d.events.close();
			}).catch((err) => error(err));
		};
		d.init();
	},

	save: function (e, grid) {
		e.preventDefault();
		var flow = grid.dataItem($(e.currentTarget).closest("tr"));
		flow.save(e);
		notification.success("[resource_displayname[saved]]");
	}
}
